// Estructura de un contacto
// { id, nombre, nif, tipo:"cliente"|"proveedor"|"ambos", telefono, email, direccion, notas, creadoEn }

function buildContactosFromFacturas(facturas) {
  const map = {};
  facturas.forEach(f => {
    const clave = (f.nif||"").trim().toUpperCase() || f.cliente.trim().toLowerCase();
    if (!clave) return;
    const tipo = f.tipo === "venta" ? "cliente" : "proveedor";
    if (!map[clave]) {
      map[clave] = { id: clave, nombre: f.cliente, nif: f.nif||"", tipo, telefono:"", email:"", direccion:"", notas:"", creadoEn: f.fecha };
    } else if (map[clave].tipo !== tipo) {
      map[clave].tipo = "ambos";
    }
  });
  return Object.values(map);
}

// Extrae o actualiza un contacto desde una factura recién guardada
function contactoFromFactura(f) {
  return {
    nombre: f.cliente,
    nif:    f.nif || "",
    tipo:   f.tipo === "venta" ? "cliente" : "proveedor",
    creadoEn: f.fecha,
  };
}

// Merge: si ya existe (mismo NIF o mismo nombre normalizado), actualiza tipo; si no, crea nuevo
function upsertContacto(lista, factura) {
  const nifNorm  = (factura.nif||"").trim().toUpperCase();
  const nomNorm  = factura.cliente.trim().toLowerCase();
  const tipoNuevo = factura.tipo === "venta" ? "cliente" : "proveedor";
  const idx = lista.findIndex(c =>
    (nifNorm && c.nif.trim().toUpperCase() === nifNorm) ||
    (!nifNorm && c.nombre.trim().toLowerCase() === nomNorm)
  );
  if (idx >= 0) {
    const existing = lista[idx];
    const nuevoTipo = existing.tipo === tipoNuevo ? existing.tipo : "ambos";
    const updated   = { ...existing, tipo: nuevoTipo, nif: nifNorm || existing.nif };
    return [...lista.slice(0,idx), updated, ...lista.slice(idx+1)];
  }
  const nuevo = { id: Date.now() + Math.random(), nombre: factura.cliente, nif: nifNorm, tipo: tipoNuevo, telefono:"", email:"", direccion:"", notas:"", creadoEn: factura.fecha };
  return [...lista, nuevo];
}

