  <table><thead><tr><th>Descripción</th><th>Cant.</th><th>P.Unit.</th><th>Dto.</th><th>Base</th><th>IVA%</th><th>Cuota IVA</th><th>R.eq.</th><th>Total línea</th></tr></thead>
  <tbody>${rows}</tbody></table>
