function openPrint(html) {
  const w = window.open("", "_blank");
  if (!w) { alert("Permite ventanas emergentes para imprimir."); return; }
  w.document.write(html); w.document.close(); w.focus();
  setTimeout(() => w.print(), 500);
}

function downloadHTML(html, filename) {
  const blob = new Blob([html], { type: "text/html;charset=utf-8" });
  const url  = URL.createObjectURL(blob);
  const a    = Object.assign(document.createElement("a"), { href: url, download: filename });
  document.body.appendChild(a); a.click();
  setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 300);
}

// Genera PDF abriendo ventana con auto-print (el navegador permite "Guardar como PDF")
// Inyecta CSS optimizado para impresión y auto-dispara el diálogo de impresión.
function downloadPDF(html, filename) {
  // Inyectar CSS de impresión mejorado y script de auto-print
  const printHtml = html
    .replace('</head>', `
<style>
@media print {
  @page { margin: 12mm 14mm; size: A4; }
  body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  .no-print { display: none !important; }
}
</style>
</head>`)
    .replace('</body>', `
<script>
  window.addEventListener('load', function() {
    setTimeout(function() {
      document.title = '${filename.replace(".pdf","")}';
      window.print();
    }, 600);
  });
<\/script>
</body>`);
  const w = window.open("", "_blank");
  if (!w) { alert("Permite ventanas emergentes para guardar el PDF."); return; }
  w.document.write(printHtml);
  w.document.close();
}

