// SELECTOR DE PERÍODO
// ════════════════════════════════════════════════════════════

function PeriodSelector({ mode, setMode, value, setValue, year, setYear, facturas=[], nominas=[] }) {
  const nowY = new Date().getFullYear();
  const yearsSet = new Set([nowY, ...facturas.map(f=>new Date(f.fecha).getFullYear()), ...nominas.map(n=>new Date(n.fecha).getFullYear())]);
  const availYears = [...yearsSet].sort((a,b)=>b-a);
  return (
    <div className="bg-white border border-gray-200 rounded-2xl px-5 py-3.5 mb-5 flex flex-wrap items-center gap-3 shadow-sm">
      <div className="flex bg-gray-100 rounded-xl p-0.5">
        {[["mes","Mes"],["trimestre","Trimestre"],["año","Año"]].map(([m,l]) => (
          <button key={m} onClick={() => { setMode(m); if(m==="mes")setValue(new Date().getMonth()); if(m==="trimestre")setValue(Math.floor(new Date().getMonth()/3)); }}
            className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${mode===m?"bg-white text-slate-900 shadow-sm":"text-gray-400 hover:text-gray-700"}`}>{l}</button>
        ))}
      </div>
      <div className="flex gap-1 flex-wrap">
        {availYears.map(y => (
          <button key={y} onClick={() => setYear(y)} className={`px-3 py-1.5 rounded-lg text-sm font-semibold border transition-all ${year===y?"bg-slate-900 text-white border-slate-900":"border-gray-200 text-gray-500 hover:border-slate-400"}`}>{y}</button>
        ))}
      </div>
      {mode==="mes" && (
        <div className="flex flex-wrap gap-1">
          {MONTHS_S.map((m,i) => (<button key={i} onClick={() => setValue(i)} className={`px-2.5 py-1 rounded-lg text-xs font-semibold transition-all ${value===i?"bg-sky-600 text-white":"bg-gray-100 text-gray-500 hover:bg-gray-200"}`}>{m}</button>))}
        </div>
      )}
      {mode==="trimestre" && (
        <div className="flex gap-1">
          {Q_LABELS.map((q,i) => (<button key={i} onClick={() => setValue(i)} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${value===i?"bg-sky-600 text-white":"bg-gray-100 text-gray-500 hover:bg-gray-200"}`}>{q}</button>))}
        </div>
      )}
      <div className="ml-auto"><span className="text-sm font-bold bg-sky-50 text-sky-700 border border-sky-200 px-3 py-1.5 rounded-lg">{getPeriodLabel(mode,value,year)}</span></div>
    </div>
  );
}

