// MODAL DETALLE NÓMINA
// ════════════════════════════════════════════════════════════

function TRow({ label, value, neg, small, bold, sep }) {
  return (
    <div className={`flex justify-between py-2 text-sm ${sep?"border-t border-gray-300 mt-1 pt-3":""} ${bold?"font-bold text-base":""} ${small?"text-xs text-gray-500":""}`}>
      <span className={bold?"text-gray-900":"text-gray-600"}>{label}</span>
      <span className={`font-mono ${neg?"text-rose-600":bold?"text-gray-900":"text-gray-800"}`}>{neg?"-":""}{fmt(value)}</span>
    </div>
  );
}

function DetalleNominaModal({ nomina, trabajadores, onClose, onDelete }) {
  if (!nomina) return null;
  const c  = calcNomina(nomina);
  const tw = trabajadores.find(t => t.id === nomina.trabajadorId) || {};
  const html = buildNominaPrintHTML(nomina, tw);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4" style={{background:"rgba(15,23,42,0.6)",backdropFilter:"blur(6px)"}}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[92vh] flex flex-col overflow-hidden">
        <div className="flex items-center justify-between px-6 py-4 bg-violet-700 text-white flex-shrink-0">
          <div className="flex items-center gap-3">
            <span className="bg-white bg-opacity-20 text-xs font-bold uppercase px-2 py-0.5 rounded-lg">Nómina</span>
            <span className="text-lg font-black truncate">{nomina.trabajadorNombre}</span>
            <span className="text-sm opacity-70">{MONTHS[nomina.mes]} {nomina.anio}</span>
          </div>
          <div className="flex gap-1.5">
            <button onClick={() => openPrint(html)} className="flex items-center gap-1.5 bg-white bg-opacity-15 hover:bg-opacity-30 text-white text-xs font-bold px-3 py-2 rounded-lg">{Ico.print} Imprimir</button>
            <button onClick={() => downloadPDF(html, `nomina-${nomina.trabajadorNombre.replace(/ /g,"-")}-${MONTHS[nomina.mes]}.pdf`)} className="flex items-center gap-1.5 bg-white bg-opacity-15 hover:bg-opacity-30 text-white text-xs font-bold px-3 py-2 rounded-lg">{Ico.pdf} PDF</button>
            <button onClick={() => downloadHTML(html, `nomina-${nomina.trabajadorNombre.replace(/ /g,"-")}-${MONTHS[nomina.mes]}.html`)} className="flex items-center gap-1.5 bg-white bg-opacity-15 hover:bg-opacity-30 text-white text-xs font-bold px-3 py-2 rounded-lg">{Ico.down} HTML</button>
            <button onClick={() => { if(confirm("¿Eliminar nómina?")){ onDelete(nomina.id); onClose(); } }} className="flex items-center gap-1.5 bg-white bg-opacity-15 hover:bg-red-600 text-white text-xs font-bold px-3 py-2 rounded-lg">{Ico.trash}</button>
            <button onClick={onClose} className="ml-1 text-white opacity-60 hover:opacity-100 text-2xl font-bold leading-none">✕</button>
          </div>
        </div>
        <div className="overflow-y-auto flex-1 p-6 space-y-5">
          <div className="grid grid-cols-2 gap-4">
            <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
              <div className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5">Trabajador</div>
              <div className="text-base font-bold text-gray-900">{nomina.trabajadorNombre}</div>
              {tw.nif&&<div className="text-sm text-gray-500 font-mono">NIF: {tw.nif}</div>}
              {tw.categoria&&<Tag color="violet">{tw.categoria}</Tag>}
            </div>
            <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
              <div className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-1.5">Período</div>
              <div className="text-base font-bold">{MONTHS[nomina.mes]} {nomina.anio}</div>
              <div className="text-sm text-gray-500">{nomina.concepto}</div>
              <Tag color={nomina.estado==="pagada"?"green":"amber"}>{nomina.estado==="pagada"?"Pagada":"Pendiente"}</Tag>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-5">
            <div>
              <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Devengos</div>
              <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-4">
                <TRow label="Salario base" value={c.bruto}/>
                {c.extras>0&&<TRow label="Complementos" value={c.extras}/>}
                <TRow label="Total devengado" value={c.baseTotal} bold/>
              </div>
              <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-2 mt-4">Deducciones trabajador</div>
              <div className="bg-rose-50 border border-rose-200 rounded-xl p-4">
                <TRow label={`SS Cont. comunes (${fmtP(SS.trabajador.contingencias)})`} value={c.ssContingencias} neg small/>
                <TRow label={`SS Desempleo (${fmtP(SS.trabajador.desempleo)})`} value={c.ssDesempleo} neg small/>
                <TRow label={`SS Formación (${fmtP(SS.trabajador.formacion)})`} value={c.ssFormacion} neg small/>
                <TRow label={`IRPF (${fmtP(nomina.irpfPct)})`} value={c.irpfAmt} neg small/>
                <TRow label="Total deducciones" value={c.totalDeduc} neg bold/>
              </div>
              <div className="bg-violet-50 border border-violet-300 rounded-xl p-4 mt-4">
                <div className="flex justify-between items-center">
                  <span className="font-black text-violet-900 text-sm">LÍQUIDO A PERCIBIR</span>
                  <span className="font-black text-violet-900 text-xl font-mono">{fmt(c.liquidoNeto)}</span>
                </div>
              </div>
            </div>
            <div>
              <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-2">Coste empresa</div>
              <div className="bg-gray-50 border border-gray-200 rounded-xl p-4">
                <TRow label={`Cont. comunes (${fmtP(SS.empresa.contingencias)})`} value={c.ssEmpContingencias} small/>
                <TRow label={`Desempleo (${fmtP(SS.empresa.desempleo)})`} value={c.ssEmpDesempleo} small/>
                <TRow label={`FOGASA (${fmtP(SS.empresa.fogasa)})`} value={c.ssEmpFogasa} small/>
                <TRow label={`Formación (${fmtP(SS.empresa.formacion)})`} value={c.ssEmpFormacion} small/>
                <TRow label="SS empresa total" value={c.ssEmpresa} bold/>
              </div>
              <div className="bg-slate-900 rounded-xl p-4 mt-4">
                <div className="text-xs font-semibold text-slate-400 uppercase tracking-widest mb-2">Coste total empresa</div>
                <div className="flex justify-between items-baseline">
                  <span className="text-slate-300 text-sm">Bruto + SS</span>
                  <span className="font-black text-white text-2xl font-mono">{fmt(c.costeEmpresa)}</span>
                </div>
              </div>
              <div className="bg-indigo-50 border border-indigo-200 rounded-xl p-4 mt-3 space-y-1 text-xs text-indigo-700">
                <div className="font-bold text-xs uppercase tracking-widest mb-1.5">Mod. 111 trimestral</div>
                <div className="flex justify-between"><span>IRPF a ingresar</span><span className="font-bold font-mono">{fmt(c.irpfAmt)}</span></div>
                <div className="flex justify-between"><span>SS total (trab.+emp.)</span><span className="font-bold font-mono">{fmt(c.ssTrab+c.ssEmpresa)}</span></div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

