function LineaRow({ linea, idx, onChange, onRemove, modoRecibida }) {
  const c = calcLinea(linea);
  const recargoPct = RECARGO_MAP[parseInt(linea.tipoIVA)] || 0;
  return (
    <div className="bg-gray-50 border border-gray-200 rounded-xl p-3 mb-2">
      {/* Fila 1: descripción + cantidades */}
      <div className="grid grid-cols-12 gap-2 mb-2">
        <div className="col-span-5">
          <label className="text-xs text-gray-500 block mb-1">Descripción del producto / servicio</label>
          <input className="w-full border rounded-lg px-3 py-1.5 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={linea.descripcion} onChange={e=>onChange(idx,"descripcion",e.target.value)} placeholder="Producto o servicio"/>
        </div>
        <div className="col-span-2">
          <label className="text-xs text-gray-500 block mb-1">Cantidad</label>
          <input type="number" min="0" step="0.01" className="w-full border rounded-lg px-3 py-1.5 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={linea.cantidad} onChange={e=>onChange(idx,"cantidad",e.target.value)}/>
        </div>
        <div className="col-span-2">
          <label className="text-xs text-gray-500 block mb-1">Precio unit.</label>
          <input type="number" min="0" step="0.01" className="w-full border rounded-lg px-3 py-1.5 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={linea.precioUnitario} onChange={e=>onChange(idx,"precioUnitario",e.target.value)}/>
        </div>
        <div className="col-span-2">
          <label className="text-xs text-gray-500 block mb-1">% Dto.</label>
          <input type="number" min="0" max="100" step="0.1" className="w-full border rounded-lg px-3 py-1.5 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={linea.descuento} onChange={e=>onChange(idx,"descuento",e.target.value)}/>
        </div>
        <div className="col-span-1 flex items-end justify-center pb-1">
          <button onClick={() => onRemove(idx)} className="text-gray-300 hover:text-rose-500 text-xl leading-none">×</button>
        </div>
      </div>
      {/* Fila 2: IVA + recargo + totales */}
      <div className="flex flex-wrap items-center gap-3">
        <div className="flex items-center gap-2">
          <select className="border rounded-lg px-3 py-1.5 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={linea.tipoIVA}
            onChange={e => {
              const v = parseInt(e.target.value);
              onChange(idx,"tipoIVA",v);
              onChange(idx,"exento",TIPOS_IVA.find(t=>t.value===v)?.exento||false);
            }}>
            {TIPOS_IVA.map(t=><option key={t.value} value={t.value}>{t.label}</option>)}
          </select>
          {/* Recargo de equivalencia por línea - solo para documentos recibidos */}
          {modoRecibida && !linea.exento && (
            <label className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg border cursor-pointer text-xs font-semibold transition-colors select-none ${linea.aplicarRecargo?"bg-amber-50 border-amber-300 text-amber-800":"bg-white border-gray-200 text-gray-500 hover:border-amber-300"}`}>
              <input type="checkbox" className="accent-amber-600" checked={!!linea.aplicarRecargo}
                onChange={e=>onChange(idx,"aplicarRecargo",e.target.checked)}/>
              Rec. equiv. {recargoPct>0?`(${recargoPct}%)`:""}
            </label>
          )}
        </div>
        {/* Desglose de la línea */}
        <div className="flex flex-wrap gap-3 text-xs text-gray-500 ml-auto items-center">
          {linea.descuento>0&&<span>Dto: <strong className="text-rose-600">-{fmt(c.descAmt)}</strong></span>}
          <span>Base: <strong className="text-gray-800">{fmt(c.baseConDesc)}</strong></span>
          {!linea.exento&&<span>IVA {linea.tipoIVA}%: <strong className="text-sky-700">{fmt(c.ivaAmt)}</strong></span>}
          {linea.exento&&<span className="text-gray-400 italic">Exento de IVA</span>}
          {c.recargoAmt>0&&<span className="text-amber-700">R.eq. {recargoPct}%: <strong>{fmt(c.recargoAmt)}</strong></span>}
          <span className="font-bold text-gray-900 bg-white border border-gray-200 rounded-lg px-2 py-0.5">
            {fmt(c.baseConDesc + c.ivaAmt + c.recargoAmt)}
          </span>
        </div>
      </div>
    </div>
  );
}

// Resumen fiscal agrupado por tipo de IVA
function ResumenFiscalIVA({ lineas, retencionPct, aplicarRecargo }) {
  const grupos = groupByIVA(lineas, aplicarRecargo);
  const tot    = calcFactura(lineas, retencionPct, aplicarRecargo);
  if (grupos.length === 0) return null;
  return (
    <div className="bg-gray-50 border border-gray-200 rounded-xl overflow-hidden mt-3">
      <div className="px-4 py-2 bg-gray-100 border-b border-gray-200">
        <span className="text-xs font-black uppercase tracking-widest text-gray-500">Desglose fiscal por tipo de IVA</span>
      </div>
      <table className="w-full text-xs">
        <thead>
          <tr className="border-b border-gray-200">
            {["Tipo IVA","Base imponible","Cuota IVA","Rec. equiv.","Subtotal"].map((h,i)=>(
              <th key={i} className={`py-2 px-3 font-semibold text-gray-500 ${i===0?"text-left":"text-right"}`}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {grupos.map((g,i)=>(
            <tr key={i} className="border-b border-gray-100">
              <td className="py-2 px-3">
                {g.exento
                  ? <span className="bg-gray-100 text-gray-500 px-2 py-0.5 rounded font-semibold">Exento</span>
                  : <span className="flex flex-wrap items-center gap-1.5">
                      <span className="bg-sky-100 text-sky-800 px-2 py-0.5 rounded font-semibold">{g.tipoIVA}%</span>
                      {g.conRecargo && <span className="bg-amber-100 text-amber-800 px-2 py-0.5 rounded font-semibold text-xs">+R.eq.{g.recargoPct}%</span>}
                    </span>
                }
              </td>
              <td className="py-2 px-3 text-right font-mono text-gray-700">{fmt(g.base)}</td>
              <td className="py-2 px-3 text-right font-mono text-sky-700">{g.exento?"—":fmt(g.ivaAmt)}</td>
              <td className="py-2 px-3 text-right font-mono text-amber-700">{g.recargoAmt>0?fmt(g.recargoAmt):"—"}</td>
              <td className="py-2 px-3 text-right font-mono font-semibold text-gray-900">{fmt(g.base+g.ivaAmt+g.recargoAmt)}</td>
            </tr>
          ))}
        </tbody>
        <tfoot className="bg-gray-100">
          <tr>
            <td className="py-2.5 px-3 text-xs font-black text-gray-700 uppercase">Totales</td>
            <td className="py-2.5 px-3 text-right font-black font-mono text-gray-900">{fmt(tot.totalBase)}</td>
            <td className="py-2.5 px-3 text-right font-black font-mono text-sky-800">{fmt(tot.totalIVA)}</td>
            <td className="py-2.5 px-3 text-right font-black font-mono text-amber-800">{tot.totalRecargo>0?fmt(tot.totalRecargo):"—"}</td>
            <td className="py-2.5 px-3 text-right font-black font-mono text-gray-900">
              {fmt(tot.totalBase+tot.totalIVA+tot.totalRecargo)}
              {tot.totalRetencion>0&&<div className="text-orange-600 text-xs">-{fmt(tot.totalRetencion)} IRPF</div>}
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
}

