function CampoContacto({ label, field, placeholder, type="text", mono=false, area=false, formData, setFormData }) {
  return (
    <div>
      <label className="block text-xs font-semibold text-gray-600 mb-1">{label}</label>
      {area ? (
        <textarea className="w-full border border-gray-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none resize-none" rows={2}
          placeholder={placeholder} value={formData[field]||""} onChange={e => setFormData(p => ({...p,[field]:e.target.value}))}/>
      ) : (
        <input type={type} className={`w-full border border-gray-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none ${mono?"font-mono":""}`}
          placeholder={placeholder} value={formData[field]||""} onChange={e => setFormData(p => ({...p,[field]:e.target.value}))}/>
      )}
    </div>
  );
}

function VistaContactos({ contactos, setContactos, facturas, onView, onSaveContacto, onDeleteContacto }) {
  const [search,    setSearch]    = useState("");
  const [filtroTipo, setFiltroTipo] = useState("todos");
  const [editando,  setEditando]  = useState(null);
  const [form,      setForm]      = useState({});
  const [verFichaId, setVerFichaId] = useState(null);
  const [showNewForm, setShowNewForm] = useState(false);
  const [editFullId, setEditFullId] = useState(null);
  const [newForm, setNewForm] = useState({ nombre:"", nif:"", tipo:"cliente", telefono:"", email:"", direccion:"", direccion_fiscal:"", codigo_postal:"", ciudad:"", provincia:"", iban:"", banco:"", persona_contacto:"", web:"", notas:"" });
  const [saving, setSaving] = useState(false);

  const filtered = useMemo(() => {
    let list = [...contactos];
    if (filtroTipo !== "todos") list = list.filter(c => c.tipo === filtroTipo || (filtroTipo === "ambos" && c.tipo === "ambos"));
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(c =>
        c.nombre.toLowerCase().includes(q) ||
        (c.nif||"").toLowerCase().includes(q) ||
        (c.telefono||"").includes(q) ||
        (c.email||"").toLowerCase().includes(q) ||
        facturas.filter(f => f.cliente.toLowerCase() === c.nombre.toLowerCase())
          .some(f => f.lineas.some(l => l.descripcion.toLowerCase().includes(q))) ||
        facturas.filter(f => f.cliente.toLowerCase() === c.nombre.toLowerCase())
          .some(f => String(calcFactura(f.lineas,f.retencionPct,f.aplicarRecargo).total).includes(q)) ||
        facturas.filter(f => f.cliente.toLowerCase() === c.nombre.toLowerCase())
          .some(f => f.fecha.includes(q))
      );
    }
    return list.sort((a,b) => a.nombre.localeCompare(b.nombre, "es"));
  }, [contactos, search, filtroTipo, facturas]);

  const startEdit = (c) => { setEditando(c.id); setForm({...c}); };
  const cancelEdit = () => { setEditando(null); setForm({}); };
  const saveEdit = async () => {
    const updated = { ...contactos.find(c => c.id === editando), ...form };
    if (onSaveContacto) {
      setSaving(true);
      const saved = await onSaveContacto(updated);
      setContactos(p => p.map(c => c.id === editando ? saved : c));
      setSaving(false);
    } else {
      setContactos(p => p.map(c => c.id === editando ? updated : c));
    }
    setEditando(null);
  };
  const deleteContact = async (id) => {
    if (!confirm("¿Eliminar este contacto del directorio?")) return;
    if (onDeleteContacto) {
      const ok = await onDeleteContacto(id);
      if (ok) setContactos(p => p.filter(c => c.id !== id));
    } else {
      setContactos(p => p.filter(c => c.id !== id));
    }
  };

  const openEditFull = (c) => {
    setEditFullId(c.id);
    setNewForm({ nombre: c.nombre||"", nif: c.nif||"", tipo: c.tipo||"cliente", telefono: c.telefono||"", email: c.email||"", direccion: c.direccion||"", direccion_fiscal: c.direccion_fiscal||"", codigo_postal: c.codigo_postal||"", ciudad: c.ciudad||"", provincia: c.provincia||"", iban: c.iban||"", banco: c.banco||"", persona_contacto: c.persona_contacto||"", web: c.web||"", notas: c.notas||"" });
    setShowNewForm(true);
  };

  const resetNewForm = () => {
    setNewForm({ nombre:"", nif:"", tipo:"cliente", telefono:"", email:"", direccion:"", direccion_fiscal:"", codigo_postal:"", ciudad:"", provincia:"", iban:"", banco:"", persona_contacto:"", web:"", notas:"" });
    setEditFullId(null);
  };

  const handleNewContact = async () => {
    if (!newForm.nombre.trim()) { alert("El nombre es obligatorio"); return; }
    setSaving(true);
    if (onSaveContacto) {
      const toSave = editFullId ? { ...newForm, id: editFullId } : newForm;
      const saved = await onSaveContacto(toSave);
      if (saved && saved.id) {
        if (editFullId) {
          setContactos(p => p.map(c => c.id === editFullId ? saved : c));
        } else {
          setContactos(p => [...p, saved]);
        }
      }
    }
    setSaving(false);
    setShowNewForm(false);
    resetNewForm();
  };

  const fichaContacto = verFichaId ? contactos.find(c => c.id === verFichaId) : null;
  const fichaFacturas = fichaContacto
    ? facturas.filter(f => f.cliente.trim().toLowerCase() === fichaContacto.nombre.trim().toLowerCase())
        .sort((a,b) => new Date(b.fecha) - new Date(a.fecha))
    : [];

  const tipoBadge = (t) => {
    if (t === "cliente")   return <Tag color="green">Cliente</Tag>;
    if (t === "proveedor") return <Tag color="red">Proveedor</Tag>;
    return <Tag color="violet">Cliente y proveedor</Tag>;
  };

  return (
    <div className="space-y-5">
      {/* Modal: Formulario nuevo/editar contacto */}
      {showNewForm && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4" onClick={() => { setShowNewForm(false); resetNewForm(); }}>
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="px-6 py-5 border-b border-gray-200 flex items-center justify-between">
              <div>
                <h2 className="text-lg font-black text-gray-900">{editFullId ? "Editar contacto" : "Nuevo contacto"}</h2>
                <p className="text-xs text-gray-400 mt-0.5">Registra un cliente o proveedor con todos sus datos fiscales</p>
              </div>
              <button onClick={() => { setShowNewForm(false); resetNewForm(); }} className="text-gray-400 hover:text-gray-700 p-1 rounded-lg hover:bg-gray-100 text-lg font-bold">✕</button>
            </div>
            <div className="px-6 py-5 space-y-5">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <CampoContacto formData={newForm} setFormData={setNewForm} label="Nombre / Razon social *" field="nombre" placeholder="Ej: Distribuciones Garcia SL"/>
                <CampoContacto formData={newForm} setFormData={setNewForm} label="NIF / CIF / DNI / NIE *" field="nif" placeholder="Ej: B12345678" mono/>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div>
                  <label className="block text-xs font-semibold text-gray-600 mb-1">Tipo *</label>
                  <select className="w-full border border-gray-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
                    value={newForm.tipo} onChange={e => setNewForm(p => ({...p, tipo:e.target.value}))}>
                    <option value="cliente">Cliente</option>
                    <option value="proveedor">Proveedor</option>
                    <option value="ambos">Cliente y proveedor</option>
                  </select>
                </div>
                <CampoContacto formData={newForm} setFormData={setNewForm} label="Persona de contacto" field="persona_contacto" placeholder="Nombre del contacto"/>
                <CampoContacto formData={newForm} setFormData={setNewForm} label="Web" field="web" placeholder="www.ejemplo.com"/>
              </div>
              <div className="border-t border-gray-100 pt-4">
                <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-3">Datos de contacto</div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <CampoContacto formData={newForm} setFormData={setNewForm} label="Telefono" field="telefono" placeholder="Ej: 965 123 456" type="tel"/>
                  <CampoContacto formData={newForm} setFormData={setNewForm} label="Email" field="email" placeholder="email@ejemplo.com" type="email"/>
                </div>
              </div>
              <div className="border-t border-gray-100 pt-4">
                <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-3">Direccion fiscal</div>
                <div className="grid grid-cols-1 gap-4">
                  <CampoContacto formData={newForm} setFormData={setNewForm} label="Direccion" field="direccion" placeholder="Calle, numero, piso..."/>
                  <div className="grid grid-cols-3 gap-4">
                    <CampoContacto formData={newForm} setFormData={setNewForm} label="Codigo postal" field="codigo_postal" placeholder="03001"/>
                    <CampoContacto formData={newForm} setFormData={setNewForm} label="Ciudad" field="ciudad" placeholder="Alicante"/>
                    <CampoContacto formData={newForm} setFormData={setNewForm} label="Provincia" field="provincia" placeholder="Alicante"/>
                  </div>
                </div>
              </div>
              <div className="border-t border-gray-100 pt-4">
                <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-3">Datos bancarios</div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <CampoContacto formData={newForm} setFormData={setNewForm} label="IBAN" field="iban" placeholder="ES00 0000 0000 0000 0000 0000" mono/>
                  <CampoContacto formData={newForm} setFormData={setNewForm} label="Banco / Entidad" field="banco" placeholder="Nombre del banco"/>
                </div>
              </div>
              <div className="border-t border-gray-100 pt-4">
                <CampoContacto formData={newForm} setFormData={setNewForm} label="Notas / Observaciones" field="notas" placeholder="Informacion adicional..." area/>
              </div>
            </div>
            <div className="px-6 py-4 border-t border-gray-200 flex justify-end gap-3">
              <button onClick={() => { setShowNewForm(false); resetNewForm(); }} className="px-5 py-2.5 text-sm font-semibold text-gray-600 border border-gray-200 rounded-xl hover:bg-gray-50">Cancelar</button>
              <button onClick={handleNewContact} disabled={saving} className="px-6 py-2.5 text-sm font-black bg-emerald-600 text-white rounded-xl hover:bg-emerald-500 shadow-lg disabled:opacity-60">
                {saving ? "Guardando..." : (editFullId ? "Actualizar contacto" : "Guardar contacto")}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Ficha / historial */}
      {fichaContacto && (
        <div className="fixed inset-0 bg-black/40 z-50 flex items-center justify-center p-4" onClick={() => setVerFichaId(null)}>
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto" onClick={e => e.stopPropagation()}>
            <div className="px-6 py-5 border-b border-gray-200 flex items-start justify-between gap-4">
              <div>
                <div className="flex items-center gap-2 mb-1">{tipoBadge(fichaContacto.tipo)}</div>
                <h2 className="text-xl font-black text-gray-900">{fichaContacto.nombre}</h2>
                <div className="text-xs text-gray-400 mt-0.5 flex gap-3 flex-wrap">
                  {fichaContacto.nif && <span className="font-mono">{fichaContacto.nif}</span>}
                  {fichaContacto.telefono && <span>{fichaContacto.telefono}</span>}
                  {fichaContacto.email && <span>{fichaContacto.email}</span>}
                </div>
              </div>
              <div className="flex gap-2 flex-shrink-0">
                <button onClick={() => { setVerFichaId(null); openEditFull(fichaContacto); }} className="text-xs font-bold text-amber-600 hover:text-amber-800 px-3 py-1.5 rounded-lg hover:bg-amber-50 border border-amber-200">Editar</button>
                <button onClick={() => setVerFichaId(null)} className="text-gray-400 hover:text-gray-700 p-1 rounded-lg hover:bg-gray-100 text-lg font-bold">✕</button>
              </div>
            </div>
            <div className="px-6 py-3 grid grid-cols-2 gap-x-6 gap-y-1.5 text-xs border-b border-gray-100">
              {fichaContacto.persona_contacto && <div><span className="text-gray-400">Contacto:</span> <span className="text-gray-700">{fichaContacto.persona_contacto}</span></div>}
              {fichaContacto.direccion && <div><span className="text-gray-400">Direccion:</span> <span className="text-gray-700">{fichaContacto.direccion}</span></div>}
              {(fichaContacto.ciudad || fichaContacto.codigo_postal) && <div><span className="text-gray-400">Ciudad:</span> <span className="text-gray-700">{fichaContacto.ciudad}{fichaContacto.codigo_postal ? ` (${fichaContacto.codigo_postal})` : ""}</span></div>}
              {fichaContacto.provincia && <div><span className="text-gray-400">Provincia:</span> <span className="text-gray-700">{fichaContacto.provincia}</span></div>}
              {fichaContacto.iban && <div><span className="text-gray-400">IBAN:</span> <span className="text-gray-700 font-mono">{fichaContacto.iban}</span></div>}
              {fichaContacto.banco && <div><span className="text-gray-400">Banco:</span> <span className="text-gray-700">{fichaContacto.banco}</span></div>}
              {fichaContacto.web && <div><span className="text-gray-400">Web:</span> <span className="text-gray-700">{fichaContacto.web}</span></div>}
            </div>
            {fichaContacto.notas && (
              <div className="px-6 py-2 bg-amber-50 border-b border-amber-100 text-xs text-amber-800">{fichaContacto.notas}</div>
            )}
            <div className="px-6 py-4">
              <div className="text-xs font-black uppercase tracking-widest text-gray-400 mb-3">Historial de facturas ({fichaFacturas.length})</div>
              {fichaFacturas.length === 0 ? (
                <div className="text-sm text-gray-400 text-center py-8">Sin facturas registradas</div>
              ) : (
                <div className="space-y-2">
                  {fichaFacturas.map(f => {
                    const t = calcFacturaReal(f);
                    const isV = f.tipo === "venta";
                    return (
                      <div key={f.id} className="flex items-center gap-3 px-4 py-3 rounded-xl border border-gray-100 hover:bg-gray-50 cursor-pointer" onClick={() => { setVerFichaId(null); onView && onView(f); }}>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2">
                            <span className="font-mono text-xs font-bold text-gray-600">{f.numero}</span>
                            <Tag color={isV?"green":"red"}>{isV?"Venta":"Gasto"}</Tag>
                          </div>
                          <div className="text-xs text-gray-400 mt-0.5">
                            {new Date(f.fecha).toLocaleDateString("es-ES")} · {f.lineas.map(l=>l.descripcion).filter(Boolean).join(", ").slice(0,60)}
                          </div>
                        </div>
                        <div className={`font-black font-mono text-sm ${isV?"text-emerald-700":"text-rose-600"}`}>{fmt(t.total)}</div>
                        <Tag color={(isV?!f.cobrado:!f.pagado)?"orange":"green"}>{(isV?!f.cobrado:!f.pagado)?"Pendiente":"Pagada"}</Tag>
                      </div>
                    );
                  })}
                  {fichaFacturas.length > 0 && (
                    <div className="pt-2 text-right text-xs text-gray-500">
                      Total facturado: <span className="font-black text-gray-800 font-mono">
                        {fmt(fichaFacturas.reduce((s,f)=>s+calcFacturaReal(f).total,0))}
                      </span>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Cabecera y filtros */}
      <div className="bg-white border border-gray-200 rounded-2xl p-5 shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
          <div>
            <h2 className="text-lg font-black text-gray-900">Directorio de contactos</h2>
            <p className="text-xs text-gray-400 mt-0.5">Clientes y proveedores con datos fiscales completos</p>
          </div>
          <div className="flex gap-2 items-center">
            <KPI label="Total" value={String(contactos.length)} sub="contactos"/>
            <KPI label="Clientes" value={String(contactos.filter(c=>c.tipo==="cliente"||c.tipo==="ambos").length)} tint="green"/>
            <KPI label="Proveedores" value={String(contactos.filter(c=>c.tipo==="proveedor"||c.tipo==="ambos").length)} tint="red"/>
            <button onClick={() => { resetNewForm(); setShowNewForm(true); }}
              className="ml-2 flex items-center gap-1.5 px-4 py-2.5 text-sm font-black bg-emerald-600 text-white rounded-xl hover:bg-emerald-500 shadow-lg">
              {Ico.plus} Nuevo contacto
            </button>
          </div>
        </div>
        <div className="flex flex-wrap gap-3">
          <div className="relative flex-1 min-w-56">
            <input className="w-full border rounded-xl px-4 py-2.5 text-sm focus:ring-2 focus:ring-slate-300 outline-none pr-10"
              placeholder="Buscar por nombre, NIF/CIF/DNI/NIE, telefono, producto, fecha o importe..."
              value={search} onChange={e => setSearch(e.target.value)}/>
            <span className="absolute right-3 top-2.5 text-gray-300">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
            </span>
          </div>
          {["todos","cliente","proveedor","ambos"].map(t => (
            <button key={t} onClick={() => setFiltroTipo(t)}
              className={`px-4 py-2 rounded-xl text-sm font-semibold border transition-all ${filtroTipo===t?"bg-slate-900 text-white border-slate-900":"border-gray-200 text-gray-500 hover:border-slate-300"}`}>
              { {todos:"Todos",cliente:"Clientes",proveedor:"Proveedores",ambos:"Ambos"}[t] }
            </button>
          ))}
        </div>
        {search && <div className="mt-2 text-xs text-gray-500">{filtered.length} resultado{filtered.length!==1?"s":""} para "{search}"</div>}
      </div>

      {/* Tabla */}
      {filtered.length === 0 ? (
        <div className="text-center py-20 bg-white border border-gray-100 rounded-2xl">
          <div className="text-5xl mb-3">👥</div>
          <div className="text-sm font-semibold text-gray-400">
            {search ? `Sin resultados para "${search}"` : "Sin contactos aun."}
          </div>
          <button onClick={() => { resetNewForm(); setShowNewForm(true); }} className="mt-4 px-5 py-2.5 text-sm font-black bg-emerald-600 text-white rounded-xl hover:bg-emerald-500">
            Registrar primer contacto
          </button>
        </div>
      ) : (
        <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
          <table className="w-full text-sm">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                {["Nombre / Razon social","NIF / CIF / DNI","Tipo","Telefono","Email","Facturas","Acciones"].map((h,i) => (
                  <th key={i} className={`py-3 px-4 text-xs font-semibold text-gray-500 uppercase tracking-wide ${i<4?"text-left":"text-right"} ${i===6?"text-center":""}`}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {filtered.map(c => {
                const cFacts = facturas.filter(f => f.cliente.trim().toLowerCase() === c.nombre.trim().toLowerCase());
                const isEdit = editando === c.id;
                return (
                  <tr key={c.id} className="border-t border-gray-100 hover:bg-slate-50 group">
                    <td className="py-3 px-4">
                      {isEdit
                        ? <input className="w-full border rounded-lg px-2 py-1 text-sm focus:ring-2 focus:ring-slate-300 outline-none" value={form.nombre||""} onChange={e=>setForm(p=>({...p,nombre:e.target.value}))}/>
                        : <button onClick={() => setVerFichaId(c.id)} className="font-semibold text-gray-900 hover:text-sky-700 text-left transition-colors">{c.nombre}</button>
                      }
                    </td>
                    <td className="py-3 px-4">
                      {isEdit
                        ? <input className="w-full border rounded-lg px-2 py-1 text-sm font-mono focus:ring-2 focus:ring-slate-300 outline-none" value={form.nif||""} onChange={e=>setForm(p=>({...p,nif:e.target.value}))}/>
                        : <span className="font-mono text-xs text-gray-500">{c.nif || <span className="italic text-gray-300">Sin NIF</span>}</span>
                      }
                    </td>
                    <td className="py-3 px-4">{tipoBadge(c.tipo)}</td>
                    <td className="py-3 px-4">
                      {isEdit
                        ? <input className="w-full border rounded-lg px-2 py-1 text-sm focus:ring-2 focus:ring-slate-300 outline-none" value={form.telefono||""} onChange={e=>setForm(p=>({...p,telefono:e.target.value}))} placeholder="Telefono"/>
                        : <span className="text-xs text-gray-500">{c.telefono || <span className="italic text-gray-300">-</span>}</span>
                      }
                    </td>
                    <td className="py-3 px-4 text-right">
                      {isEdit
                        ? <input className="w-full border rounded-lg px-2 py-1 text-sm focus:ring-2 focus:ring-slate-300 outline-none" value={form.email||""} onChange={e=>setForm(p=>({...p,email:e.target.value}))} placeholder="Email"/>
                        : <span className="text-xs text-gray-500">{c.email || <span className="italic text-gray-300">-</span>}</span>
                      }
                    </td>
                    <td className="py-3 px-4 text-right">
                      <button onClick={() => setVerFichaId(c.id)} className="text-xs text-sky-600 hover:text-sky-800 font-semibold">
                        {cFacts.length} factura{cFacts.length!==1?"s":""}
                      </button>
                    </td>
                    <td className="py-3 px-4">
                      <div className="flex gap-1 justify-center">
                        {isEdit ? (
                          <>
                            <button onClick={saveEdit} disabled={saving} className="p-1.5 rounded-lg text-emerald-600 hover:bg-emerald-50 text-xs font-bold" title="Guardar">{Ico.check}</button>
                            <button onClick={cancelEdit} className="p-1.5 rounded-lg text-gray-400 hover:bg-gray-100 text-xs" title="Cancelar">✕</button>
                          </>
                        ) : (
                          <>
                            <button onClick={() => setVerFichaId(c.id)} className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-slate-500 hover:text-slate-900 hover:bg-slate-100 transition-all" title="Ver ficha">{Ico.eye}</button>
                            <button onClick={() => openEditFull(c)} className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-amber-500 hover:text-amber-700 hover:bg-amber-50 transition-all" title="Editar completo">{Ico.edit}</button>
                            <button onClick={() => deleteContact(c.id)} className="p-1.5 rounded-lg opacity-0 group-hover:opacity-100 text-rose-400 hover:text-rose-600 hover:bg-rose-50 transition-all" title="Eliminar">{Ico.trash}</button>
                          </>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      <div className="text-xs text-gray-400 text-center px-4 pb-2">
        Los contactos se registran automaticamente al crear facturas o puedes darlos de alta manualmente con "Nuevo contacto".
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// FORMULARIO FACTURA EMITIDA (empresa → cliente)
// ════════════════════════════════════════════════════════════

function FacturaEmitidaForm({ actividades, facturas, onSave, onCancel, initial, logo, setLogo, contactos=[] }) {
  const autoNum = useMemo(() => genNumeroFactura(facturas, cy), [facturas]);
  const empDef = useMemo(() => getEmpresaDefaults(), []);
  const EMPTY = {
    modo:"emitida", tipo:"venta", tipoDoc:"factura",
    numero:autoNum, fecha:today(), cliente:"", nif:"", actividad:actividades[0]||"",
    lineas:[{descripcion:"",cantidad:1,precioUnitario:0,tipoIVA:21,exento:false,descuento:0,aplicarRecargo:false}],
    retencionPct:0, aplicarRecargo:false, notas:"", cobrado:false, pagado:false,
    ibanEmpresa:empDef.iban||"", bancoEmpresa:empDef.banco||"",
    empresaNombre:empDef.nombre||"", empresaNif:empDef.nif||"",
    empresaDireccion:empDef.direccion||"", empresaTelefono:empDef.telefono||"",
    empresaEmail:empDef.email||"",
  };
  const [f, setF] = useState(() => initial ? {...initial} : {...EMPTY});
  const fileRef   = useRef();
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const upd = (i,k,v) => setF(p=>{const ls=[...p.lineas];ls[i]={...ls[i],[k]:v};return{...p,lineas:ls};});
  const add = () => setF(p=>({...p,lineas:[...p.lineas,{descripcion:"",cantidad:1,precioUnitario:0,tipoIVA:21,exento:false,descuento:0,aplicarRecargo:false}]}));
  const rem = (i) => setF(p=>({...p,lineas:p.lineas.filter((_,j)=>j!==i)}));
  const tot = calcFactura(f.lineas, f.retencionPct, false);
  const handleLogo = (e) => { const file=e.target.files[0]; if(!file)return; const r=new FileReader(); r.onload=ev=>setLogo(ev.target.result); r.readAsDataURL(file); };
  const save = () => {
    if (!f.numero.trim()) { alert("Número de factura obligatorio."); return; }
    if (!f.empresaNombre.trim()) { alert("Nombre/razón social del emisor obligatorio para validez legal."); return; }
    if (!f.empresaNif.trim()) { alert("NIF/CIF del emisor obligatorio para validez legal."); return; }
    if (!f.cliente.trim()){ alert("Cliente obligatorio."); return; }
    if (!f.fecha)         { alert("Fecha obligatoria."); return; }
    setEmpresaDefaults({
      nombre: f.empresaNombre, nif: f.empresaNif, direccion: f.empresaDireccion,
      telefono: f.empresaTelefono, email: f.empresaEmail,
      iban: f.ibanEmpresa, banco: f.bancoEmpresa,
    });
    onSave(f);
  };
  return (
    <div className="bg-white rounded-2xl border border-gray-200 p-6 max-w-5xl mx-auto shadow-sm">
      {/* Cabecera */}
      <div className="flex items-start justify-between mb-6 gap-6">
        <div className="flex-1">
          <div className="flex items-center gap-2 mb-1">
            <span className="bg-emerald-600 text-white text-xs font-black px-2.5 py-1 rounded-lg uppercase tracking-wide">Factura emitida</span>
            <span className="text-xs text-gray-400">Empresa → Cliente</span>
          </div>
          <h2 className="text-xl font-black text-gray-900">{initial?"Editar factura":"Nueva factura de empresa"}</h2>
          <p className="text-xs text-gray-400 mt-0.5">Numeración automática DC-{cy}/NNNN · Con logotipo oficial de la empresa</p>
        </div>
        {/* Logo de empresa */}
        <div className="flex-shrink-0 text-center">
          <div className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-2">Logotipo empresa</div>
          <div className="relative border-2 border-dashed border-gray-300 hover:border-emerald-400 rounded-xl w-44 h-20 flex items-center justify-center cursor-pointer overflow-hidden bg-gray-50 transition-colors"
            onClick={() => fileRef.current.click()}>
            {logo
              ? <img src={logo} alt="logo" className="w-full h-full object-contain p-2"/>
              : <div className="text-center text-gray-400"><div className="flex justify-center mb-1">{Ico.img}</div><span className="text-xs">Subir logo</span></div>
            }
          </div>
          <input ref={fileRef} type="file" accept="image/*" className="hidden" onChange={handleLogo}/>
          {logo && <button onClick={() => setLogo(null)} className="mt-1 text-xs text-rose-400 hover:text-rose-600">Quitar logo</button>}
          <p className="text-xs text-gray-400 mt-1">Aparece en el PDF impreso</p>
        </div>
      </div>

      {/* Datos del emisor (obligatorios para validez legal) */}
      <div className="mb-5 p-4 bg-indigo-50 rounded-xl border border-indigo-200">
        <div className="flex items-center gap-2 mb-3">
          <span className="text-xs font-black text-indigo-800 uppercase tracking-wide">Datos del emisor</span>
          <span className="text-xs text-indigo-500">(obligatorios art. 6 RD 1619/2012)</span>
        </div>
        <div className="grid grid-cols-3 gap-3">
          <div className="col-span-2">
            <label className="text-xs font-semibold text-gray-600 block mb-1">Nombre / Razón social *</label>
            <input className="w-full border border-indigo-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-indigo-300 outline-none"
              value={f.empresaNombre||""} onChange={e=>set("empresaNombre",e.target.value)} placeholder="Tu nombre o razón social"/>
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-600 block mb-1">NIF / CIF *</label>
            <input className="w-full border border-indigo-200 rounded-lg px-3 py-2 text-sm font-mono bg-white focus:ring-2 focus:ring-indigo-300 outline-none"
              value={f.empresaNif||""} onChange={e=>set("empresaNif",e.target.value.toUpperCase())} placeholder="12345678A"/>
          </div>
          <div className="col-span-2">
            <label className="text-xs font-semibold text-gray-600 block mb-1">Domicilio fiscal</label>
            <input className="w-full border border-indigo-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-indigo-300 outline-none"
              value={f.empresaDireccion||""} onChange={e=>set("empresaDireccion",e.target.value)} placeholder="Calle, número, CP, ciudad, provincia"/>
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-600 block mb-1">Teléfono</label>
            <input className="w-full border border-indigo-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-indigo-300 outline-none"
              value={f.empresaTelefono||""} onChange={e=>set("empresaTelefono",e.target.value)} placeholder="600 000 000"/>
          </div>
          <div className="col-span-2">
            <label className="text-xs font-semibold text-gray-600 block mb-1">Email</label>
            <input type="email" className="w-full border border-indigo-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-indigo-300 outline-none"
              value={f.empresaEmail||""} onChange={e=>set("empresaEmail",e.target.value)} placeholder="tu@empresa.com"/>
          </div>
        </div>
        <p className="text-xs text-indigo-400 mt-2">Estos datos se guardan y se rellenan solos en la próxima factura.</p>
      </div>

      {/* Campos principales */}
      <div className="grid grid-cols-3 gap-4 mb-5">
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Número de factura</label>
          <input className="w-full border rounded-xl px-3 py-2 text-sm font-mono font-bold bg-sky-50 border-sky-200 text-sky-800 focus:ring-2 focus:ring-sky-300 outline-none"
            value={f.numero} onChange={e=>set("numero",e.target.value)}/>
          <p className="text-xs text-sky-600 mt-1">Formato DC-{cy}/NNNN · Correlativo</p>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Fecha de emisión *</label>
          <input type="date" className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.fecha} onChange={e=>set("fecha",e.target.value)}/>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Actividad</label>
          <select className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.actividad} onChange={e=>set("actividad",e.target.value)}>
            {actividades.map(a=><option key={a} value={a}>{a}</option>)}
          </select>
        </div>
        <div className="col-span-2">
          <ClienteAutocomplete
            value={f.cliente} nif={f.nif} contactos={contactos}
            label="Cliente *" placeholder="Nombre o razón social del cliente"
            onChange={({nombre, nif}) => setF(p=>({...p, cliente:nombre, nif:nif||p.nif}))}
          />
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">NIF / CIF del cliente</label>
          <input className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.nif} onChange={e=>set("nif",e.target.value)} placeholder="B12345678"/>
        </div>
      </div>

      {/* Líneas */}
      <div className="mb-5">
        <div className="flex justify-between items-center mb-3">
          <span className="text-sm font-bold text-gray-700">Líneas de factura</span>
          <button onClick={add} className="text-xs font-bold text-sky-700 bg-sky-50 hover:bg-sky-100 border border-sky-200 px-3 py-1.5 rounded-lg">+ Añadir línea</button>
        </div>
        {f.lineas.map((l,i) => <LineaRow key={i} linea={l} idx={i} onChange={upd} onRemove={rem} modoRecibida={false}/>)}
        <ResumenFiscalIVA lineas={f.lineas} retencionPct={f.retencionPct} aplicarRecargo={false}/>
      </div>

      {/* Opciones fiscales */}
      <div className="grid grid-cols-4 gap-4 mb-5 p-4 bg-slate-50 rounded-xl border border-slate-200">
        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Retención IRPF (%)</label>
          <input type="number" min="0" max="50" step="0.01" className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.retencionPct} onChange={e=>set("retencionPct",e.target.value)}/>
          <p className="text-xs text-gray-400 mt-1">15% general · 7% inicio actividad</p>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Estado de cobro</label>
          <select className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.cobrado?"cobrada":"pendiente"} onChange={e=>set("cobrado",e.target.value==="cobrada")}>
            <option value="pendiente">Pendiente de cobro</option>
            <option value="cobrada">Cobrada</option>
          </select>
        </div>
        <div className="col-span-2">
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Notas internas</label>
          <input className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.notas} onChange={e=>set("notas",e.target.value)} placeholder="Referencia, expediente, condiciones..."/>
        </div>
      </div>

      {/* Datos bancarios */}
      <div className="grid grid-cols-2 gap-4 mb-5 p-4 bg-blue-50 rounded-xl border border-blue-200">
        <div className="col-span-2">
          <span className="text-xs font-bold text-blue-800 uppercase tracking-wide">Datos bancarios para el pago</span>
          <p className="text-xs text-blue-600 mt-0.5">Aparecen en la factura impresa. Plazo automatico: 15 dias desde recepcion.</p>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">IBAN / Cuenta bancaria</label>
          <input className="w-full border border-blue-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-blue-300 outline-none font-mono"
            value={f.ibanEmpresa||""} onChange={e=>set("ibanEmpresa",e.target.value.toUpperCase())} placeholder="ES91 2100 0418 4502 0005 1332"/>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Entidad bancaria</label>
          <input className="w-full border border-blue-200 rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-blue-300 outline-none"
            value={f.bancoEmpresa||""} onChange={e=>set("bancoEmpresa",e.target.value)} placeholder="Nombre del banco"/>
        </div>
      </div>

      {/* Total */}
      <div className="bg-emerald-50 border border-emerald-200 rounded-xl p-5 mb-5">
        <div className="grid grid-cols-2 gap-x-10 text-sm">
          <div className="space-y-2">
            <div className="flex justify-between text-gray-600"><span>Base imponible</span><span className="font-bold font-mono">{fmt(tot.totalBase)}</span></div>
            <div className="flex justify-between text-gray-600"><span>Cuota IVA</span><span className="font-bold text-sky-700 font-mono">{fmt(tot.totalIVA)}</span></div>
          </div>
          <div className="space-y-2">
            {tot.totalRetencion>0&&<div className="flex justify-between text-gray-600"><span>Retención IRPF ({f.retencionPct}%)</span><span className="font-bold text-orange-600 font-mono">-{fmt(tot.totalRetencion)}</span></div>}
            <div className="flex justify-between text-xl font-black border-t border-emerald-300 pt-2 text-emerald-800">
              <span>Total factura</span><span className="font-mono">{fmt(tot.total)}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="flex gap-3 justify-end">
        <button onClick={onCancel} className="px-5 py-2.5 text-sm font-semibold border rounded-xl text-gray-600 hover:bg-gray-50">Cancelar</button>
        <button onClick={save} className="px-6 py-2.5 text-sm font-black bg-emerald-600 text-white rounded-xl hover:bg-emerald-500 shadow-lg">
          {initial?"Guardar cambios":"Emitir factura"}
        </button>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// FORMULARIO DOCUMENTO RECIBIDO (gastos, ingresos de proveedores, autofacturas)
// ════════════════════════════════════════════════════════════

function DocumentoRecibidoForm({ actividades, onSave, onCancel, initial, contactos=[], userId }) {
  const EMPTY = {
    modo:"recibida", tipo:"gasto", tipoDoc:"factura",
    numero:"", fecha:today(), cliente:"", nif:"", actividad:actividades[0]||"",
    lineas:[{descripcion:"",cantidad:1,precioUnitario:0,tipoIVA:21,exento:false,descuento:0,aplicarRecargo:false}],
    retencionPct:0, aplicarRecargo:false, notas:"", cobrado:true, pagado:false,
  };
  const [f, setF] = useState(() => initial ? {...initial} : {...EMPTY});
  const set = (k,v) => setF(p=>({...p,[k]:v}));
  const upd = (i,k,v) => setF(p=>{const ls=[...p.lineas];ls[i]={...ls[i],[k]:v};return{...p,lineas:ls};});
  const add = () => setF(p=>({...p,lineas:[...p.lineas,{descripcion:"",cantidad:1,precioUnitario:0,tipoIVA:21,exento:false,descuento:0,aplicarRecargo:false}]}));
  const rem = (i) => setF(p=>({...p,lineas:p.lineas.filter((_,j)=>j!==i)}));
  const tot = calcFactura(f.lineas, f.retencionPct, false);
  const isIngreso = f.tipo === "venta";

  // ── Adjunto ──────────────────────────────────────────
  const [archivoFile,   setArchivoFile]   = useState(null);
  const [subiendoDoc,   setSubiendoDoc]   = useState(false);
  const [docExistente,  setDocExistente]  = useState(initial?.documento_url ? { url: initial.documento_url, nombre: initial.documento_nombre } : null);

  const handleArchivo = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (file.size > 10 * 1024 * 1024) { alert("El archivo no puede superar 10 MB."); return; }
    setArchivoFile(file);
  };

  const save = async () => {
    if (!f.cliente.trim()){ alert(`${isIngreso?"Emisor":"Proveedor"} obligatorio.`); return; }
    if (!f.fecha)         { alert("Fecha obligatoria."); return; }

    let docUrl  = docExistente?.url  || null;
    let docNombre = docExistente?.nombre || null;

    if (archivoFile && userId) {
      setSubiendoDoc(true);
      const ext  = archivoFile.name.split(".").pop();
      const path = `${userId}/${Date.now()}-${archivoFile.name.replace(/[^a-zA-Z0-9._-]/g,"_")}`;
      const { data, error } = await supabase.storage.from("documentos").upload(path, archivoFile, { upsert: false });
      setSubiendoDoc(false);
      if (error) { alert("Error al subir el archivo: " + error.message); return; }
      const { data: urlData } = supabase.storage.from("documentos").getPublicUrl(data.path);
      // Si es privado usamos signed URL en su lugar
      const { data: signed } = await supabase.storage.from("documentos").createSignedUrl(data.path, 60 * 60 * 24 * 365);
      docUrl    = signed?.signedUrl || urlData?.publicUrl || null;
      docNombre = archivoFile.name;
    }

    onSave({ ...f, documento_url: docUrl, documento_nombre: docNombre });
  };

  return (
    <div className="bg-white rounded-2xl border border-gray-200 p-6 max-w-5xl mx-auto shadow-sm">
      {/* Cabecera */}
      <div className="mb-6">
        <div className="flex items-center gap-2 mb-1">
          <span className={`text-xs font-black px-2.5 py-1 rounded-lg uppercase tracking-wide text-white ${isIngreso?"bg-sky-600":"bg-rose-600"}`}>
            {isIngreso?"Ingreso recibido":"Gasto / Compra"}
          </span>
          <span className="text-xs text-gray-400">Documento que recibes de un tercero</span>
        </div>
        <h2 className="text-xl font-black text-gray-900">{initial?"Editar documento":"Registrar documento recibido"}</h2>
        <p className="text-xs text-gray-400 mt-0.5">Introduce el número tal como figura en el documento original</p>

        {/* Tipo de movimiento */}
        <div className="flex gap-2 mt-3 flex-wrap">
          {[
            { v:"gasto",  label:"Gasto / Compra",        col:"rose"  },
            { v:"venta",  label:"Ingreso (autofactura)",  col:"sky"   },
          ].map(opt => (
            <button key={opt.v} onClick={() => set("tipo", opt.v)}
              className={`px-4 py-2 rounded-full text-sm font-bold transition-all ${f.tipo===opt.v
                ? opt.col==="rose"?"bg-rose-600 text-white shadow-md":"bg-sky-600 text-white shadow-md"
                : "bg-gray-100 text-gray-500 hover:bg-gray-200"}`}>
              {opt.label}
            </button>
          ))}
        </div>
      </div>

      {/* Tipo de documento + número + fecha + actividad */}
      <div className="grid grid-cols-4 gap-4 mb-5">
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Tipo de documento</label>
          <select className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.tipoDoc} onChange={e=>set("tipoDoc",e.target.value)}>
            {TIPOS_DOC.map(t=><option key={t.value} value={t.value}>{t.label}</option>)}
          </select>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Número del documento</label>
          <input className="w-full border rounded-xl px-3 py-2 text-sm font-mono focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.numero} onChange={e=>set("numero",e.target.value)} placeholder="Nº que figura en el documento"/>
          <p className="text-xs text-gray-400 mt-1">Cópialo exactamente del original</p>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Fecha del documento *</label>
          <input type="date" className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.fecha} onChange={e=>set("fecha",e.target.value)}/>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Actividad</label>
          <select className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.actividad} onChange={e=>set("actividad",e.target.value)}>
            {actividades.map(a=><option key={a} value={a}>{a}</option>)}
          </select>
        </div>
        <div className="col-span-2">
          <ClienteAutocomplete
            value={f.cliente} nif={f.nif} contactos={contactos}
            label={isIngreso?"Emisor (quién emite la autofactura) *":"Proveedor *"}
            placeholder={isIngreso?"Amazon, Western Union, Ría...":"Nombre o razón social del proveedor"}
            onChange={({nombre, nif}) => setF(p=>({...p, cliente:nombre, nif:nif||p.nif}))}
          />
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">NIF / CIF</label>
          <input className="w-full border rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.nif} onChange={e=>set("nif",e.target.value)} placeholder="ESB01001420"/>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">{isIngreso?"Cobrado":"Estado de pago"}</label>
          {isIngreso
            ? <select className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
                value={f.cobrado?"cobrada":"pendiente"} onChange={e=>set("cobrado",e.target.value==="cobrada")}>
                <option value="cobrada">Ingresado / Cobrado</option>
                <option value="pendiente">Pendiente de cobro</option>
              </select>
            : <select className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
                value={f.pagado?"pagada":"pendiente"} onChange={e=>set("pagado",e.target.value==="pagada")}>
                <option value="pendiente">Pendiente de pago</option>
                <option value="pagada">Pagado</option>
              </select>
          }
        </div>
      </div>

      {/* Nota recargo de equivalencia */}
      {!isIngreso && (
        <div className="mb-4 px-4 py-3 bg-amber-50 border border-amber-200 rounded-xl text-xs text-amber-900 leading-relaxed">
          <strong>Recargo de equivalencia:</strong> si estás en el régimen de recargo de equivalencia, marca la casilla en cada línea que lo lleve. El porcentaje se calcula automáticamente según el IVA: 21% IVA → 5,2% RE, 10% IVA → 1,4% RE, 4% IVA → 0,5% RE. Puedes mezclar líneas con y sin recargo en la misma factura.
        </div>
      )}

      {/* Nota autofactura */}
      {f.tipoDoc==="autofactura" && (
        <div className="mb-4 px-4 py-3 bg-sky-50 border border-sky-200 rounded-xl text-xs text-sky-800">
          <strong>Autofactura:</strong> el proveedor (Amazon, Ría, Western Union, etc.) emite la factura en tu nombre. El número es el que ellos asignan. El importe es el ingreso que recibes por tus comisiones o ventas.
        </div>
      )}

      {/* Líneas con IVA por línea y recargo de equivalencia por línea */}
      <div className="mb-2">
        <div className="flex justify-between items-center mb-2">
          <div>
            <span className="text-sm font-bold text-gray-700">Líneas del documento</span>
            <span className="ml-2 text-xs text-gray-400">Puedes usar distintos tipos de IVA por línea</span>
          </div>
          <button onClick={add} className="text-xs font-bold text-sky-700 bg-sky-50 hover:bg-sky-100 border border-sky-200 px-3 py-1.5 rounded-lg">+ Añadir línea</button>
        </div>
        {f.lineas.map((l,i) => <LineaRow key={i} linea={l} idx={i} onChange={upd} onRemove={rem} modoRecibida={true}/>)}
        <ResumenFiscalIVA lineas={f.lineas} retencionPct={f.retencionPct} aplicarRecargo={false}/>
      </div>

      {/* Opciones adicionales */}
      <div className="grid grid-cols-3 gap-4 mt-5 mb-5 p-4 bg-slate-50 rounded-xl border border-slate-200">
        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Retención IRPF (%)</label>
          <input type="number" min="0" max="50" step="0.01" className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.retencionPct} onChange={e=>set("retencionPct",e.target.value)}/>
        </div>
        <div className="col-span-2">
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Notas internas</label>
          <input className="w-full border rounded-lg px-3 py-2 text-sm bg-white focus:ring-2 focus:ring-slate-300 outline-none"
            value={f.notas} onChange={e=>set("notas",e.target.value)} placeholder="Referencia, expediente, observaciones..."/>
        </div>

        {/* Adjuntar documento */}
        <div className="col-span-2">
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Documento adjunto (PDF, imagen)</label>
          {docExistente && (
            <div className="flex items-center gap-2 mb-2 text-xs text-slate-600 bg-slate-50 border border-slate-200 rounded-lg px-3 py-2">
              <svg className="w-4 h-4 text-rose-500 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.172 7l-6.586 6.586a2 2 0 102.828 2.828l6.414-6.586a4 4 0 00-5.656-5.656l-6.415 6.585a6 6 0 108.486 8.486L20.5 13"/>
              </svg>
              <a href={docExistente.url} target="_blank" rel="noopener noreferrer" className="truncate text-blue-600 hover:underline flex-1">{docExistente.nombre || "Ver documento"}</a>
              <button onClick={()=>setDocExistente(null)} className="text-rose-400 hover:text-rose-600 font-bold ml-1">✕</button>
            </div>
          )}
          <div className="flex items-center gap-3">
            <label className="cursor-pointer flex items-center gap-2 px-4 py-2 border border-dashed border-slate-300 rounded-lg text-xs text-slate-500 hover:bg-slate-50 transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12"/>
              </svg>
              {archivoFile ? archivoFile.name : "Seleccionar archivo"}
              <input type="file" accept=".pdf,.jpg,.jpeg,.png,.webp" className="hidden" onChange={handleArchivo}/>
            </label>
            {archivoFile && <button onClick={()=>setArchivoFile(null)} className="text-xs text-rose-400 hover:text-rose-600">Quitar</button>}
          </div>
          <p className="text-xs text-slate-400 mt-1">PDF, JPG o PNG. Máximo 10 MB. Se guardará en tu cuenta.</p>
        </div>
      </div>

      {/* Total */}
      <div className={`border rounded-xl p-5 mb-5 ${isIngreso?"bg-sky-50 border-sky-200":"bg-rose-50 border-rose-200"}`}>
        <div className="grid grid-cols-2 gap-x-10 text-sm">
          <div className="space-y-2">
            <div className="flex justify-between text-gray-600"><span>Base imponible</span><span className="font-bold font-mono">{fmt(tot.totalBase)}</span></div>
            <div className="flex justify-between text-gray-600"><span>Cuota IVA {isIngreso?"repercutido":"soportado"}</span><span className="font-bold text-sky-700 font-mono">{fmt(tot.totalIVA)}</span></div>
            {tot.totalRecargo>0&&<div className="flex justify-between text-gray-600"><span>Rec. equivalencia</span><span className="font-bold text-amber-700 font-mono">{fmt(tot.totalRecargo)}</span></div>}
          </div>
          <div className="space-y-2">
            {tot.totalRetencion>0&&<div className="flex justify-between text-gray-600"><span>Retención IRPF</span><span className="font-bold text-orange-600 font-mono">-{fmt(tot.totalRetencion)}</span></div>}
            <div className={`flex justify-between text-xl font-black border-t pt-2 ${isIngreso?"border-sky-300 text-sky-800":"border-rose-300 text-rose-800"}`}>
              <span>Total documento</span><span className="font-mono">{fmt(tot.total)}</span>
            </div>
          </div>
        </div>
      </div>

      <div className="flex gap-3 justify-end">
        <button onClick={onCancel} className="px-5 py-2.5 text-sm font-semibold border rounded-xl text-gray-600 hover:bg-gray-50">Cancelar</button>
        <button onClick={save} disabled={subiendoDoc} className={`px-6 py-2.5 text-sm font-black text-white rounded-xl shadow-lg disabled:opacity-60 ${isIngreso?"bg-sky-600 hover:bg-sky-500":"bg-rose-600 hover:bg-rose-500"}`}>
          {subiendoDoc ? "Subiendo archivo..." : initial?"Guardar cambios":isIngreso?"Registrar ingreso":"Registrar gasto"}
        </button>
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// AUDITORÍA CONTABLE + VERIFICACIÓN VERIFACTU + ASESOR IA
// ════════════════════════════════════════════════════════════

const NIF_RE = /^[0-9]{8}[A-Z]$|^[A-Z][0-9]{7}[0-9A-Z]$|^[KLMXYZ][0-9]{7}[A-Z]$/i;

function ejecutarAuditoria(facturas, nominas = []) {
  const alertas = [];
  const emitidas = facturas.filter(f => f.modo === "emitida" || f.tipo === "venta").sort((a,b) => new Date(a.fecha) - new Date(b.fecha));
  const recibidas = facturas.filter(f => f.modo === "recibida" || f.tipo === "gasto");
  const todas = [...facturas].sort((a,b) => new Date(a.fecha) - new Date(b.fecha));
  const hoy = new Date();
  const anioActual = hoy.getFullYear();
  const trimestreActual = Math.floor(hoy.getMonth() / 3);

  // ── 1. NUMERACIÓN: saltos y duplicados ──
  const numeros = emitidas.map(f => f.numero);
  const dupsNum = numeros.filter((n, i) => numeros.indexOf(n) !== i);
  if (dupsNum.length > 0) alertas.push({ tipo: "error", cat: "Numeración", msg: `Facturas con número duplicado: ${[...new Set(dupsNum)].join(", ")}`, detalle: "VeriFactu exige numeración correlativa y única (art. 11 RD 1007/2023). Duplicados invalidan la cadena de hashes.", accion: "Corrige inmediatamente: emite factura rectificativa o reasigna números." });

  const dcNums = emitidas.map(f => { const m = f.numero.match(/DC-(\d{4})\/(\d+)/); return m ? { year: parseInt(m[1]), seq: parseInt(m[2]), num: f.numero } : null; }).filter(Boolean);
  const byYear = {};
  dcNums.forEach(n => { if (!byYear[n.year]) byYear[n.year] = []; byYear[n.year].push(n); });
  Object.entries(byYear).forEach(([yr, nums]) => {
    nums.sort((a,b) => a.seq - b.seq);
    for (let i = 1; i < nums.length; i++) {
      if (nums[i].seq - nums[i-1].seq > 1) {
        alertas.push({ tipo: "warn", cat: "Numeración", msg: `Salto en numeración ${yr}: de ${nums[i-1].num} a ${nums[i].num} (faltan ${nums[i].seq - nums[i-1].seq - 1})`, detalle: "Hacienda puede interpretar saltos como facturas eliminadas (art. 201 bis LGT). Sanción hasta 150 EUR por factura.", accion: "Documenta por escrito la razón del salto. Si fue error, anota en observaciones." });
      }
    }
  });

  // ── 2. NIF/CIF: ausentes o mal formados ──
  emitidas.filter(f => f.tipoDoc !== "venta_tienda").forEach(f => {
    const t = calcFacturaReal(f);
    if (!f.nif && !f.clienteNif) {
      if (t.total > 400) alertas.push({ tipo: "error", cat: "NIF", msg: `Factura ${f.numero} sin NIF del cliente (importe ${fmt(t.total)})`, detalle: "Obligatorio en facturas completas (art. 6 RD 1619/2012). Facturas simplificadas solo permiten omitir NIF si importe < 400 EUR.", accion: "Solicita NIF al cliente y actualiza la factura." });
      else alertas.push({ tipo: "info", cat: "NIF", msg: `Factura ${f.numero} sin NIF (simplificada: ${fmt(t.total)})`, detalle: "Aceptable en factura simplificada (< 400 EUR) pero recomendable tenerlo.", accion: "Recomendado: solicitar NIF igualmente para el modelo 347." });
    } else {
      const nif = (f.nif || f.clienteNif || "").trim().toUpperCase().replace(/[-\s]/g,"");
      if (nif && !NIF_RE.test(nif)) alertas.push({ tipo: "warn", cat: "NIF", msg: `NIF sospechoso en ${f.numero}: "${f.nif || f.clienteNif}"`, detalle: "No coincide con formato DNI (8 dígitos + letra), NIE (X/Y/Z + 7 dígitos + letra) ni CIF (letra + 8 caracteres).", accion: "Verifica con el cliente. NIF incorrecto invalida la deducción de IVA del receptor." });
    }
  });
  recibidas.forEach(f => {
    if (!f.nif && !f.clienteNif) alertas.push({ tipo: "warn", cat: "NIF", msg: `Gasto ${f.numero} sin NIF del proveedor`, detalle: "Sin NIF no puedes deducir el IVA soportado (art. 97.1 LIVA). La AEAT rechazará la deducción en comprobación.", accion: "Solicita factura completa con NIF al proveedor antes de presentar el 303." });
  });

  // ── 3. IVA: cálculos y tipos ──
  todas.forEach(f => {
    if (f.tipoDoc === "venta_tienda") return;
    (f.lineas || []).forEach((l, i) => {
      const tipo = parseInt(l.tipoIVA);
      if (!l.exento && ![0, 4, 10, 21].includes(tipo)) alertas.push({ tipo: "error", cat: "IVA", msg: `Tipo IVA no estándar (${tipo}%) en ${f.numero}, línea ${i+1}`, detalle: "En España solo existen IVA 0% (exento), 4% (superreducido), 10% (reducido) y 21% (general). Art. 90-91 LIVA.", accion: "Corrige el tipo de IVA en la línea afectada." });
      if (parseFloat(l.precioUnitario) === 0 && parseFloat(l.cantidad) > 0) alertas.push({ tipo: "info", cat: "Importes", msg: `Precio 0 en ${f.numero}, línea ${i+1}: "${l.descripcion}"`, detalle: "Puede ser correcto (muestra gratuita, autoconsumo) pero Hacienda vigila operaciones a precio 0.", accion: "Si es autoconsumo, debe tributar a valor de mercado (art. 79.3 LIVA)." });
    });
    const t = calcFacturaReal(f);
    if (t.totalBase < 0 && !f.esRectificativa) alertas.push({ tipo: "error", cat: "Importes", msg: `Base negativa en ${f.numero} (${fmt(t.totalBase)}) sin ser rectificativa`, detalle: "Solo las facturas rectificativas pueden tener base negativa (art. 15 RD 1619/2012).", accion: "Marca como rectificativa o corrige el importe." });
  });

  // ── 4. RETENCIÓN IRPF ──
  emitidas.filter(f => f.tipoDoc !== "venta_tienda").forEach(f => {
    const pct = parseFloat(f.retencionPct || 0);
    if (pct > 0 && ![7, 15, 1, 2, 19, 20, 24].includes(pct)) {
      alertas.push({ tipo: "warn", cat: "IRPF", msg: `Retención atípica ${pct}% en ${f.numero}`, detalle: "Tipos habituales: 7% (nuevos autónomos, art. 101.5 LIRPF primeros 3 años), 15% (general profesionales), 19-24% (rentas capital).", accion: "Verifica que el porcentaje sea correcto según tu situación." });
    }
  });
  // Profesionales sin retención
  recibidas.forEach(f => {
    const nif = (f.nif || f.clienteNif || "").trim().toUpperCase();
    const pct = parseFloat(f.retencionPct || 0);
    if (pct > 0 && !nif) {
      alertas.push({ tipo: "warn", cat: "IRPF", msg: `Gasto ${f.numero} con retención ${pct}% pero sin NIF`, detalle: "Si retienes IRPF a un profesional, necesitas su NIF para el modelo 111 y 190.", accion: "Solicita NIF del profesional e inclúyelo en la factura." });
    }
  });

  // ── 5. FECHAS ──
  todas.forEach(f => {
    const fd = new Date(f.fecha);
    if (fd > hoy) alertas.push({ tipo: "warn", cat: "Fechas", msg: `${f.numero} con fecha futura: ${fd.toLocaleDateString("es-ES")}`, detalle: "Las facturas se emiten en la fecha de la operación o antes del día 16 del mes siguiente (art. 11 RD 1619/2012).", accion: "Corrige la fecha si es un error." });
    const diasAnti = Math.floor((hoy - fd) / 86400000);
    if (diasAnti > 1460 && diasAnti <= 1825) alertas.push({ tipo: "info", cat: "Fechas", msg: `${f.numero} próxima a prescribir (${Math.floor(diasAnti/365)} años)`, detalle: "El plazo de prescripción tributaria es 4 años (art. 66 LGT). Después no puede ser inspeccionada, pero conserva 6 años por obligación mercantil.", accion: "Conserva documentación. Prescribe fiscalmente en " + Math.ceil((1461-diasAnti)/30) + " meses." });
  });

  // ── 6. DUPLICADOS ──
  const firmas = {};
  todas.forEach(f => {
    const t = calcFacturaReal(f);
    const key = `${f.fecha}_${t.total.toFixed(2)}_${(f.cliente||"").toLowerCase().trim()}`;
    if (!firmas[key]) firmas[key] = [];
    firmas[key].push(f.numero);
  });
  Object.entries(firmas).filter(([,v]) => v.length > 1).forEach(([k, nums]) => {
    alertas.push({ tipo: "warn", cat: "Duplicados", msg: `Posible duplicado: ${nums.join(" y ")} (misma fecha, importe y cliente)`, detalle: "Duplicar gastos es la irregularidad más frecuente en inspecciones a autónomos.", accion: "Revisa si son operaciones distintas. Si es duplicado, elimina la errónea." });
  });

  // ── 7. SALDOS PENDIENTES ──
  todas.forEach(f => {
    const isV = f.tipo === "venta";
    const pendiente = isV ? !f.cobrado : !f.pagado;
    if (pendiente) {
      const dias = Math.floor((hoy - new Date(f.fecha)) / 86400000);
      if (dias > 180) alertas.push({ tipo: "error", cat: "Saldos", msg: `${f.numero}: ${isV ? "sin cobrar" : "sin pagar"} desde hace ${dias} días`, detalle: isV ? "Facturas impagadas >6 meses: obligatorio provisionar por insolvencia (art. 13.1 LIS). Además, puedes solicitar modificación de base imponible del IVA (art. 80.4 LIVA)." : "Gastos pendientes de pago >6 meses generan problemas de tesorería graves.", accion: isV ? "Inicia reclamación o provisiona. Valora modificar base IVA para recuperar cuota." : "Gestiona el pago para evitar recargos del proveedor." });
      else if (dias > 60) alertas.push({ tipo: "warn", cat: "Saldos", msg: `${f.numero}: ${isV ? "sin cobrar" : "sin pagar"} desde hace ${dias} días`, detalle: isV ? "Contacta al cliente. Pasados 6 meses tienes opciones legales adicionales." : "Vigila la liquidez.", accion: isV ? "Envía recordatorio de pago al cliente." : "Programa el pago." });
    }
  });

  // ── 8. CADENA VERIFACTU ──
  const conHash = emitidas.filter(f => f.verifactuHash).sort((a,b) => (a.verifactuCadenaPos||0) - (b.verifactuCadenaPos||0));
  const sinHash = emitidas.filter(f => !f.verifactuHash && f.tipoDoc !== "venta_tienda");
  if (sinHash.length > 0 && conHash.length > 0) alertas.push({ tipo: "warn", cat: "VeriFactu", msg: `${sinHash.length} factura(s) emitida(s) sin hash VeriFactu`, detalle: "Facturas anteriores a la activación. La cadena empieza desde que se activó el sistema.", accion: "Las facturas antiguas no se pueden encadenar retroactivamente. Solo las nuevas tendrán hash." });
  for (let i = 1; i < conHash.length; i++) {
    if ((conHash[i].verifactuCadenaPos||0) - (conHash[i-1].verifactuCadenaPos||0) !== 1)
      alertas.push({ tipo: "error", cat: "VeriFactu", msg: `Salto en cadena: pos ${conHash[i-1].verifactuCadenaPos} a ${conHash[i].verifactuCadenaPos}`, detalle: "GRAVE: La cadena debe ser consecutiva. Posible manipulación o error.", accion: "Investiga qué ocurrió. Puede requerir reconstrucción de cadena." });
    if (conHash[i].verifactuHashPrevio && conHash[i].verifactuHashPrevio !== conHash[i-1].verifactuHash)
      alertas.push({ tipo: "error", cat: "VeriFactu", msg: `Rotura de cadena en ${conHash[i].numero}`, detalle: "GRAVE: el hash previo no coincide. La integridad está comprometida.", accion: "Esto puede indicar manipulación de datos. Contacta soporte técnico." });
  }

  // ── 9. ACTIVIDADES ──
  todas.filter(f => !f.actividad || f.actividad === "Sin actividad").forEach(f => {
    alertas.push({ tipo: "info", cat: "Actividades", msg: `${f.numero} sin actividad`, detalle: "Necesario para desglose en modelos 130 y 303 si tienes varias actividades.", accion: "Asigna la actividad correspondiente." });
  });

  // ── 10. VENTAS DE TIENDA ──
  const ventasTienda = emitidas.filter(f => f.tipoDoc === "venta_tienda");
  ventasTienda.forEach(f => {
    const t = calcFacturaReal(f);
    if (t.totalIVA === 0 && t.totalBase > 0) alertas.push({ tipo: "warn", cat: "IVA Tienda", msg: `Venta tienda ${f.numero} sin impuesto registrado`, detalle: "Aunque sea un resumen mensual, el IVA repercutido debe reflejarse para el modelo 303.", accion: "Edita la venta y añade el impuesto general del período." });
    if ((t.costeMercancia || 0) <= 0 && t.totalBase > 0) alertas.push({ tipo: "info", cat: "Tienda", msg: `Venta ${f.numero} sin coste de mercancía`, detalle: "Sin coste no se calcula el margen real del negocio.", accion: "Registra el coste de la mercancía vendida para tener un margen de beneficio realista." });
  });

  // ── 11. TRIMESTRE ACTUAL: prepago fiscal ──
  const factsTrimestreActual = facturas.filter(f => {
    const d = new Date(f.fecha);
    return d.getFullYear() === anioActual && Math.floor(d.getMonth()/3) === trimestreActual;
  });
  const resQ = summarizeFacturas(factsTrimestreActual);
  const ivaAPagar = resQ.ivaRep - resQ.ivaSop;
  if (ivaAPagar > 0 && resQ.ingresos > 0) {
    alertas.push({ tipo: "info", cat: "Previsión fiscal", msg: `IVA estimado trimestre actual: ${fmt(ivaAPagar)} a pagar`, detalle: `Ingresos: ${fmt(resQ.ingresos)}, IVA rep.: ${fmt(resQ.ivaRep)}, IVA sop.: ${fmt(resQ.ivaSop)}.`, accion: "Reserva esta cantidad para el modelo 303." });
  }
  const rendNeto = Math.max(0, resQ.beneficio);
  const irpfEst = rendNeto * 0.20 - resQ.retencionesSop;
  if (irpfEst > 0) {
    alertas.push({ tipo: "info", cat: "Previsión fiscal", msg: `IRPF (Mod. 130) estimado: ${fmt(irpfEst)}`, detalle: `Rendimiento neto: ${fmt(rendNeto)}, 20% = ${fmt(rendNeto*0.20)}, retenciones soportadas: -${fmt(resQ.retencionesSop)}.`, accion: "Reserva para el pago fraccionado." });
  }

  // ── 12. NÓMINAS ──
  if (nominas.length > 0) {
    const nominasMesActual = nominas.filter(n => n.mes === hoy.getMonth() && n.anio === anioActual);
    const trabajadoresActivos = [...new Set(nominas.map(n => n.trabajadorNombre))];
    if (nominasMesActual.length === 0 && trabajadoresActivos.length > 0) {
      alertas.push({ tipo: "warn", cat: "Nóminas", msg: `No hay nóminas registradas para ${MONTHS[hoy.getMonth()]} ${anioActual}`, detalle: "Si tienes trabajadores activos, las nóminas deben estar al día.", accion: "Genera las nóminas del mes actual." });
    }
  }

  // ── PUNTUACIÓN ──
  const errores = alertas.filter(a => a.tipo === "error").length;
  const avisos = alertas.filter(a => a.tipo === "warn").length;
  const info = alertas.filter(a => a.tipo === "info").length;
  let nota = 10;
  nota -= errores * 2;
  nota -= avisos * 0.5;
  nota -= info * 0.1;
  nota = Math.max(0, Math.min(10, Math.round(nota * 10) / 10));

  return { alertas, errores, avisos, info, nota, totalFacturas: todas.length, totalEmitidas: emitidas.length, totalRecibidas: recibidas.length, conHash: conHash.length, sinHash: sinHash.length, resumenTrimestre: { ivaAPagar, irpfEst, ingresos: resQ.ingresos, gastos: resQ.gastos, beneficio: resQ.beneficio } };
}

function generarResumenParaIA(facturas, nominas = []) {
  const hoy = new Date();
  const anio = hoy.getFullYear();
  const mes = hoy.getMonth();
  const trimestre = Math.floor(mes / 3);
  const trimestreNombre = ["1T","2T","3T","4T"][trimestre];

  // Datos anuales
  const factsAnio = facturas.filter(f => new Date(f.fecha).getFullYear() === anio);
  const resAnio = summarizeFacturas(factsAnio);

  // Datos trimestrales
  const factsTrim = facturas.filter(f => { const d = new Date(f.fecha); return d.getFullYear() === anio && Math.floor(d.getMonth()/3) === trimestre; });
  const resTrim = summarizeFacturas(factsTrim);

  // Datos mensuales (últimos 3 meses)
  const meses3 = [];
  for (let i = 2; i >= 0; i--) {
    const m = new Date(anio, mes - i, 1);
    const mf = facturas.filter(f => { const d = new Date(f.fecha); return d.getMonth() === m.getMonth() && d.getFullYear() === m.getFullYear(); });
    const r = summarizeFacturas(mf);
    meses3.push({ mes: MONTHS[m.getMonth()], anio: m.getFullYear(), ingresos: r.ingresos, gastos: r.gastos, ivaRep: r.ivaRep, ivaSop: r.ivaSop, beneficio: r.beneficio, nFacturas: mf.length });
  }

  // Saldos pendientes
  const pendCobro = facturas.filter(f => f.tipo === "venta" && !f.cobrado);
  const pendPago = facturas.filter(f => f.tipo === "gasto" && !f.pagado);
  const totalPendCobro = pendCobro.reduce((s,f) => s + calcFacturaReal(f).total, 0);
  const totalPendPago = pendPago.reduce((s,f) => s + calcFacturaReal(f).total, 0);

  // Por actividad
  const porAct = {};
  factsAnio.forEach(f => {
    const act = f.actividad || "Sin actividad";
    if (!porAct[act]) porAct[act] = { ingresos: 0, gastos: 0, n: 0 };
    const t = calcFacturaReal(f);
    if (f.tipo === "venta") porAct[act].ingresos += t.totalBase;
    else porAct[act].gastos += t.totalBase;
    porAct[act].n++;
  });

  // Top clientes y proveedores
  const clientes = {}, proveedores = {};
  factsAnio.forEach(f => {
    const nombre = f.cliente || "Desconocido";
    const t = calcFacturaReal(f);
    if (f.tipo === "venta") { if (!clientes[nombre]) clientes[nombre] = 0; clientes[nombre] += t.totalBase; }
    else { if (!proveedores[nombre]) proveedores[nombre] = 0; proveedores[nombre] += t.totalBase; }
  });
  const topClientes = Object.entries(clientes).sort((a,b) => b[1]-a[1]).slice(0,5);
  const topProveedores = Object.entries(proveedores).sort((a,b) => b[1]-a[1]).slice(0,5);

  // Nóminas
  const nominasInfo = nominas.length > 0 ? {
    total: nominas.length,
    costeMensual: nominas.filter(n => n.mes === mes && n.anio === anio).reduce((s,n) => s + calcNomina(n).costeEmpresa, 0),
    trabajadores: [...new Set(nominas.map(n => n.trabajadorNombre))].length
  } : null;

  // VeriFactu
  const conHash = facturas.filter(f => f.verifactuHash).length;
  const totalEmitidas = facturas.filter(f => f.tipo === "venta").length;

  const fmtN = n => n.toFixed(2);

  return `DATOS CONTABLES DEL AUTÓNOMO - FECHA: ${hoy.toLocaleDateString("es-ES")}

RESUMEN ANUAL ${anio}:
- Ingresos totales (base): ${fmtN(resAnio.ingresos)} EUR
- Gastos totales (base): ${fmtN(resAnio.gastos)} EUR
- Beneficio bruto: ${fmtN(resAnio.beneficio)} EUR
- IVA repercutido acumulado: ${fmtN(resAnio.ivaRep)} EUR
- IVA soportado acumulado: ${fmtN(resAnio.ivaSop)} EUR
- Retenciones IRPF soportadas: ${fmtN(resAnio.retencionesSop)} EUR
- Total facturas emitidas: ${factsAnio.filter(f=>f.tipo==="venta").length}
- Total facturas recibidas: ${factsAnio.filter(f=>f.tipo==="gasto").length}

TRIMESTRE ACTUAL (${trimestreNombre} ${anio}):
- Ingresos: ${fmtN(resTrim.ingresos)} EUR
- Gastos: ${fmtN(resTrim.gastos)} EUR
- IVA a pagar estimado (Mod. 303): ${fmtN(resTrim.ivaRep - resTrim.ivaSop)} EUR
- IRPF estimado (Mod. 130): ${fmtN(Math.max(0, resTrim.beneficio * 0.20 - resTrim.retencionesSop))} EUR

EVOLUCIÓN ÚLTIMOS 3 MESES:
${meses3.map(m => `${m.mes} ${m.anio}: Ingresos ${fmtN(m.ingresos)}, Gastos ${fmtN(m.gastos)}, Beneficio ${fmtN(m.beneficio)}, Facturas: ${m.nFacturas}`).join("\n")}

SALDOS PENDIENTES:
- Facturas por cobrar: ${pendCobro.length} (${fmtN(totalPendCobro)} EUR)
- Facturas por pagar: ${pendPago.length} (${fmtN(totalPendPago)} EUR)
- Saldo neto pendiente: ${fmtN(totalPendCobro - totalPendPago)} EUR
${pendCobro.filter(f => Math.floor((hoy - new Date(f.fecha))/86400000) > 60).length > 0 ? `- ALERTA: ${pendCobro.filter(f => Math.floor((hoy - new Date(f.fecha))/86400000) > 60).length} facturas por cobrar con más de 60 días` : ""}

DESGLOSE POR ACTIVIDAD:
${Object.entries(porAct).map(([act, d]) => `${act}: Ingresos ${fmtN(d.ingresos)}, Gastos ${fmtN(d.gastos)}, Margen ${d.ingresos > 0 ? ((d.ingresos-d.gastos)/d.ingresos*100).toFixed(1) : 0}%, Facturas: ${d.n}`).join("\n")}

TOP CLIENTES: ${topClientes.map(([n,v]) => `${n} (${fmtN(v)} EUR)`).join(", ") || "Sin datos"}
TOP PROVEEDORES: ${topProveedores.map(([n,v]) => `${n} (${fmtN(v)} EUR)`).join(", ") || "Sin datos"}

${nominasInfo ? `NÓMINAS: ${nominasInfo.trabajadores} trabajador(es), coste empresa mes actual: ${fmtN(nominasInfo.costeMensual)} EUR` : "Sin trabajadores registrados."}

VERIFACTU: ${conHash} de ${totalEmitidas} facturas emitidas con hash SHA-256.
RATIO GASTOS/INGRESOS: ${resAnio.ingresos > 0 ? (resAnio.gastos/resAnio.ingresos*100).toFixed(1) : "N/A"}%
MARGEN NETO: ${resAnio.ingresos > 0 ? ((resAnio.beneficio)/resAnio.ingresos*100).toFixed(1) : "N/A"}%`;
}

function VistaAuditoria({ facturas, nominas = [] }) {
  const [tab, setTab] = useState("chequeo");
  const [resultado, setResultado] = useState(null);
  const [filtro, setFiltro] = useState("todos");
  // IA
  const [iaLoading, setIaLoading] = useState(false);
  const [iaResultado, setIaResultado] = useState(null);
  const [iaError, setIaError] = useState(null);

  const ejecutar = () => { setResultado(ejecutarAuditoria(facturas, nominas)); };
  useEffect(() => { if (facturas.length > 0) ejecutar(); }, []);

  const lanzarIA = async () => {
    setIaLoading(true); setIaError(null); setIaResultado(null);
    const resumen = generarResumenParaIA(facturas, nominas);
    const auditoria = resultado || ejecutarAuditoria(facturas, nominas);
    const alertasTexto = auditoria.alertas.map(a => `[${a.tipo.toUpperCase()}] ${a.cat}: ${a.msg} - ${a.detalle}`).join("\n");

    const prompt = `Eres un asesor fiscal colegiado especializado en autónomos españoles (régimen de estimación directa simplificada). Tu cliente te ha dado acceso a su sistema contable y necesita tu análisis profesional y recomendaciones concretas.

${resumen}

ALERTAS DEL SISTEMA DE AUDITORÍA AUTOMÁTICA:
${alertasTexto || "Sin alertas."}
Nota automática: ${auditoria.nota}/10

Tu misión: analiza estos datos como si estuvieras preparando una reunión trimestral con tu cliente. Sé directo, práctico y honesto. No uses lenguaje de marketing, ni eufemismos. Si hay problemas, dílos claramente. Si las cosas van bien, dilo también sin exagerar.

Responde con este formato exacto (usa # para secciones):

# Diagnóstico rápido
En 3-4 frases, la situación real del negocio. ¿Va bien? ¿Hay riesgos? ¿Qué tendencia ves? Sé concreto con números.

# Salud fiscal
Analiza la situación ante Hacienda: ¿están los impuestos al día? ¿El ratio gastos/ingresos es razonable o levantará sospechas en inspección? ¿Los modelos trimestrales cuadrarán? Si hay ventas de tienda, ¿el IVA está bien reflejado? Cita artículos de ley cuando sea relevante.

# Análisis de rentabilidad
¿Qué actividades son rentables y cuáles no? ¿El margen es sostenible? ¿Los gastos están controlados? ¿Hay dependencia excesiva de un solo cliente? Usa los datos reales.

# Tesorería y cobros
¿La liquidez es suficiente para afrontar los pagos fiscales del trimestre? ¿Los pendientes de cobro son preocupantes? ¿Hay que reclamar algo?

# Problemas detectados
Lista los problemas reales que has encontrado, ordenados por gravedad. Para cada uno: qué es, por qué importa y qué hacer. No repitas las alertas automáticas, aporta tu criterio profesional sobre ellas.

# Plan de acción (próximos 30 días)
5-8 acciones concretas, priorizadas, con plazo orientativo. Cada una debe ser algo que el autónomo pueda hacer realmente, no consejos genéricos. Si hay que contratar un gestor para algo, dilo.

# Preparación VeriFactu
Estado actual de preparación. Qué falta para cumplir antes de julio 2027. Si el sistema ya cubre lo básico (hash chain, QR, inmutabilidad), indícalo y señala lo que aún requiere software certificado.

Escribe en español de España, tono profesional pero cercano. Tutea al cliente. Máximo 1500 palabras.`;

    try {
      const txt = await callAI({ messages: [{ role: "user", content: prompt }], max_tokens: 3000 });
      setIaResultado(txt);
    } catch (err) {
      setIaError(err.message || "Error al conectar con la IA. Inténtalo de nuevo.");
    }
    setIaLoading(false);
  };

  const r = resultado;
  const notaColor = r ? (r.nota >= 8 ? "text-emerald-600" : r.nota >= 5 ? "text-amber-600" : "text-rose-600") : "text-gray-400";
  const notaBg = r ? (r.nota >= 8 ? "from-emerald-50 to-emerald-100 border-emerald-200" : r.nota >= 5 ? "from-amber-50 to-amber-100 border-amber-200" : "from-rose-50 to-rose-100 border-rose-200") : "from-gray-50 to-gray-100 border-gray-200";

  // Renderizar markdown básico
  const renderMD = (txt) => {
    if (!txt) return null;
    return txt.split("\n").map((line, i) => {
      if (line.startsWith("# ")) return <h2 key={i} className="text-lg font-black text-slate-900 mt-6 mb-2 first:mt-0">{line.slice(2)}</h2>;
      if (line.startsWith("## ")) return <h3 key={i} className="text-base font-bold text-slate-800 mt-4 mb-1">{line.slice(3)}</h3>;
      if (line.startsWith("- ")) return <div key={i} className="flex gap-2 ml-2 mb-1"><span className="text-slate-400 mt-0.5">-</span><span className="text-sm text-slate-700">{line.slice(2)}</span></div>;
      if (line.trim() === "") return <div key={i} className="h-2"/>;
      return <p key={i} className="text-sm text-slate-700 leading-relaxed mb-1.5">{line}</p>;
    });
  };

  return (
    <div className="space-y-6">
      {/* Cabecera */}
      <div className={`bg-gradient-to-br ${notaBg} border rounded-2xl p-6`}>
        <div className="flex items-center justify-between flex-wrap gap-4">
          <div>
            <h2 className="text-xl font-black text-gray-900 mb-1">Auditoría contable y fiscal</h2>
            <p className="text-xs text-gray-500">{r ? `${r.totalFacturas} facturas analizadas (${r.totalEmitidas} emitidas, ${r.totalRecibidas} recibidas)` : "Cargando..."}</p>
          </div>
          <div className="text-center">
            <div className={`text-5xl font-black font-mono ${notaColor}`}>{r ? r.nota : "-"}</div>
            <div className="text-xs font-bold text-gray-500">/10</div>
          </div>
        </div>
        {r && (
          <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mt-4">
            {[
              { label: "Errores", v: r.errores, text: "text-rose-700" },
              { label: "Avisos", v: r.avisos, text: "text-amber-700" },
              { label: "Info", v: r.info, text: "text-sky-700" },
              { label: "VeriFactu", v: `${r.conHash}/${r.totalEmitidas}`, text: "text-emerald-700" },
              { label: "IVA trim.", v: fmt(r.resumenTrimestre.ivaAPagar), text: r.resumenTrimestre.ivaAPagar > 0 ? "text-rose-700" : "text-emerald-700" },
            ].map(item => (
              <div key={item.label} className="bg-white bg-opacity-70 rounded-xl p-3 text-center">
                <div className={`text-xl font-black font-mono ${item.text}`}>{item.v}</div>
                <div className="text-[10px] font-bold text-gray-500 uppercase tracking-wider">{item.label}</div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 bg-slate-100 p-1 rounded-xl">
        {[
          { id: "chequeo", label: "Chequeo automático" },
          { id: "ia", label: "Asesor IA" },
        ].map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`flex-1 py-2.5 text-sm font-bold rounded-lg transition-all ${tab === t.id ? "bg-white text-slate-900 shadow-sm" : "text-slate-500 hover:text-slate-700"}`}>
            {t.label}
          </button>
        ))}
      </div>

      {/* TAB: Chequeo automático */}
      {tab === "chequeo" && r && (() => {
        const filtradas = filtro === "todos" ? r.alertas : r.alertas.filter(a => a.tipo === filtro);
        const cats = [...new Set(r.alertas.map(a => a.cat))];
        return (
          <div className="space-y-4">
            <div className="flex gap-2 flex-wrap">
              {[
                { id: "todos", label: `Todos (${r.alertas.length})` },
                { id: "error", label: `Errores (${r.errores})`, color: "bg-rose-100 text-rose-700 border-rose-300" },
                { id: "warn", label: `Avisos (${r.avisos})`, color: "bg-amber-100 text-amber-700 border-amber-300" },
                { id: "info", label: `Info (${r.info})`, color: "bg-sky-100 text-sky-700 border-sky-300" },
              ].map(f => (
                <button key={f.id} onClick={() => setFiltro(f.id)}
                  className={`px-3 py-1.5 text-xs font-bold rounded-lg border transition-all ${filtro === f.id ? (f.color || "bg-slate-900 text-white border-slate-900") : "bg-white text-gray-600 border-gray-200 hover:border-gray-400"}`}>
                  {f.label}
                </button>
              ))}
              <div className="flex-1"/>
              <button onClick={ejecutar} className="px-3 py-1.5 text-xs font-bold rounded-lg bg-slate-100 text-slate-700 hover:bg-slate-200 border border-slate-200">Analizar de nuevo</button>
            </div>
            {filtradas.length === 0 ? (
              <div className="text-center py-12 bg-white border border-gray-100 rounded-2xl">
                <div className="text-4xl mb-2">✅</div>
                <div className="text-sm font-semibold text-gray-500">Sin alertas en esta categoría</div>
              </div>
            ) : (
              <div className="space-y-3">
                {cats.filter(c => filtradas.some(a => a.cat === c)).map(cat => (
                  <div key={cat} className="bg-white border border-gray-200 rounded-xl overflow-hidden">
                    <div className="px-4 py-2.5 bg-gray-50 border-b border-gray-200 flex items-center gap-2">
                      <span className="text-xs font-black text-gray-600 uppercase tracking-wider">{cat}</span>
                      <span className="text-xs text-gray-400">({filtradas.filter(a => a.cat === cat).length})</span>
                    </div>
                    <div className="divide-y divide-gray-100">
                      {filtradas.filter(a => a.cat === cat).map((a, i) => (
                        <div key={i} className="px-4 py-3 flex gap-3 items-start">
                          <div className={`w-2 h-2 rounded-full mt-1.5 flex-shrink-0 ${a.tipo === "error" ? "bg-rose-500" : a.tipo === "warn" ? "bg-amber-500" : "bg-sky-400"}`}/>
                          <div className="flex-1 min-w-0">
                            <div className="text-sm font-semibold text-gray-800">{a.msg}</div>
                            <div className="text-xs text-gray-500 mt-0.5">{a.detalle}</div>
                            {a.accion && <div className="text-xs text-indigo-700 mt-1 bg-indigo-50 px-2 py-1 rounded-md inline-block">{a.accion}</div>}
                          </div>
                          <span className={`text-[10px] font-bold uppercase px-2 py-0.5 rounded-md flex-shrink-0 ${a.tipo === "error" ? "bg-rose-100 text-rose-700" : a.tipo === "warn" ? "bg-amber-100 text-amber-700" : "bg-sky-100 text-sky-700"}`}>
                            {a.tipo === "error" ? "CRÍTICO" : a.tipo === "warn" ? "AVISO" : "INFO"}
                          </span>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        );
      })()}

      {/* TAB: Asesor IA */}
      {tab === "ia" && (
        <div className="space-y-4">
          {!iaResultado && !iaLoading && (
            <div className="bg-white border border-gray-200 rounded-2xl p-8 text-center">
              <div className="w-16 h-16 mx-auto mb-4 bg-gradient-to-br from-indigo-500 to-violet-600 rounded-2xl flex items-center justify-center">
                <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z"/></svg>
              </div>
              <h3 className="text-lg font-black text-gray-900 mb-2">Asesor fiscal IA</h3>
              <p className="text-sm text-gray-500 max-w-lg mx-auto mb-6">
                La IA analizará tu contabilidad completa: ingresos, gastos, IVA, retenciones, saldos pendientes, rentabilidad por actividad y estado VeriFactu. Recibirás un informe con diagnóstico, problemas y un plan de acción concreto.
              </p>
              <button onClick={lanzarIA}
                className="bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-8 py-3 rounded-xl font-black text-sm hover:from-indigo-500 hover:to-violet-500 shadow-lg shadow-indigo-200 transition-all">
                Lanzar análisis IA
              </button>
            </div>
          )}
          {iaLoading && (
            <div className="bg-white border border-gray-200 rounded-2xl p-12 text-center">
              <div className="animate-spin w-10 h-10 border-4 border-indigo-200 border-t-indigo-600 rounded-full mx-auto mb-4"/>
              <div className="text-sm font-bold text-gray-700">Analizando tu contabilidad...</div>
              <div className="text-xs text-gray-400 mt-1">La IA está revisando facturas, IVA, retenciones, saldos y rentabilidad</div>
            </div>
          )}
          {iaError && (
            <div className="bg-rose-50 border border-rose-200 rounded-2xl p-6">
              <div className="text-sm font-bold text-rose-700 mb-2">Error en el análisis</div>
              <div className="text-xs text-rose-600 mb-4">{iaError}</div>
              <button onClick={lanzarIA} className="bg-rose-600 text-white px-4 py-2 rounded-lg text-xs font-bold hover:bg-rose-700">Reintentar</button>
            </div>
          )}
          {iaResultado && (
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <div className="text-xs text-gray-500">Análisis generado: {new Date().toLocaleString("es-ES")}</div>
                <div className="flex gap-2">
                  <button onClick={lanzarIA} className="px-3 py-1.5 text-xs font-bold rounded-lg bg-indigo-100 text-indigo-700 hover:bg-indigo-200 border border-indigo-200">Nuevo análisis</button>
                  <button onClick={() => {
                    const html = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Informe Asesor Fiscal IA</title>
                    <style>@page{margin:20mm}body{font-family:'Helvetica Neue',Arial,sans-serif;font-size:12px;color:#1e293b;line-height:1.7;max-width:700px;margin:0 auto}
                    h1{font-size:20px;font-weight:900;color:#0f172a;border-bottom:3px solid #0f172a;padding-bottom:8px;margin-top:24px}
                    h2{font-size:15px;font-weight:800;color:#1e293b;margin-top:20px}
                    p{margin:6px 0}
                    .hdr{background:#0f172a;color:#fff;padding:24px;border-radius:12px;margin-bottom:24px}
                    .hdr h1{color:#fff;border:none;margin:0;font-size:18px}
                    .footer{margin-top:32px;padding:16px;background:#f1f5f9;border-radius:8px;font-size:10px;color:#64748b}
                    </style></head><body>
                    <div class="hdr"><h1>Informe del Asesor Fiscal IA</h1><div style="font-size:10px;opacity:.7;margin-top:4px">${new Date().toLocaleDateString("es-ES")} · ContaAuto</div></div>
                    ${iaResultado.replace(/^# (.+)$/gm,"<h1>$1</h1>").replace(/^## (.+)$/gm,"<h2>$1</h2>").replace(/^- (.+)$/gm,"<p style='margin-left:16px'>• $1</p>").replace(/\n\n/g,"<br/><br/>").replace(/\n/g,"<br/>")}
                    <div class="footer">Aviso legal: este informe es orientativo y no constituye asesoramiento fiscal vinculante. Consulta con un asesor fiscal colegiado antes de tomar decisiones tributarias. Generado con ContaAuto.</div>
                    </body></html>`;
                    downloadPDF(html, `informe-fiscal-ia-${new Date().toISOString().slice(0,10)}.pdf`);
                  }} className="px-3 py-1.5 text-xs font-bold rounded-lg bg-slate-900 text-white hover:bg-slate-700">Descargar PDF</button>
                </div>
              </div>
              <div className="bg-white border border-gray-200 rounded-2xl p-6 md:p-8">
                {renderMD(iaResultado)}
              </div>
            </div>
          )}
        </div>
      )}

      {/* Nota legal */}
      <div className="bg-slate-50 border border-slate-200 rounded-xl p-4 text-xs text-slate-500">
        <strong className="text-slate-700">Aviso legal:</strong> Esta auditoría es orientativa. No sustituye la revisión de un asesor fiscal colegiado. ContaAuto implementa medidas preparatorias para VeriFactu (hash chain SHA-256, QR, inmutabilidad) pero NO es software certificado por la AEAT. Obligatoriedad para autónomos: 1 julio 2027 (RD 254/2025). Los análisis de la IA son aproximaciones basadas en los datos registrados y no tienen carácter vinculante.
      </div>
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// FORMULARIO: VENTAS DE TIENDA - RESUMEN MENSUAL
// ════════════════════════════════════════════════════════════

const MESES_NOMBRE = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];

function VentaTiendaForm({ facturas, onSave, onCancel, initial }) {
  const hoy = new Date();
  const mesAnt = hoy.getMonth() === 0 ? 11 : hoy.getMonth() - 1;
  const anioAnt = hoy.getMonth() === 0 ? hoy.getFullYear() - 1 : hoy.getFullYear();

  const [mes, setMes] = useState(() => initial ? new Date(initial.fecha).getMonth() : mesAnt);
  const [anio, setAnio] = useState(() => initial ? new Date(initial.fecha).getFullYear() : anioAnt);
  const [subtotal, setSubtotal] = useState(() => {
    if (!initial) return "";
    const base = (initial.lineas||[])[0]?.precioUnitario || 0;
    return base > 0 ? String(base) : "";
  });
  const [impuesto, setImpuesto] = useState(() => initial ? String(initial.impuestoManual || "") : "");
  const [coste, setCoste] = useState(() => initial ? String(initial.costeMercancia || "") : "");
  const [notas, setNotas] = useState(() => initial?.notas || "");

  const sub = parseFloat(subtotal) || 0;
  const imp = parseFloat(impuesto) || 0;
  const cos = parseFloat(coste) || 0;
  const totalVenta = sub + imp;
  const beneficio = sub - cos;

  // Verificar si ya existe un registro para ese mes
  const yaExiste = facturas.some(f =>
    f.tipoDoc === "venta_tienda" &&
    new Date(f.fecha).getMonth() === mes &&
    new Date(f.fecha).getFullYear() === anio &&
    (!initial || f.id !== initial.id)
  );

  const save = () => {
    if (sub <= 0) { alert("El subtotal debe ser mayor que 0."); return; }
    if (yaExiste) { alert("Ya existe un registro de ventas de tienda para " + MESES_NOMBRE[mes] + " " + anio + "."); return; }
    // Ultimo dia del mes seleccionado
    const fecha = new Date(anio, mes + 1, 0).toISOString().split("T")[0];
    const periodo = MESES_NOMBRE[mes] + " " + anio;
    onSave({
      modo: "emitida",
      tipo: "venta",
      tipoDoc: "venta_tienda",
      numero: "TIENDA-" + anio + "/" + String(mes + 1).padStart(2, "0"),
      fecha,
      cliente: "Ventas Tienda (resumen)",
      nif: "",
      actividad: "Tienda",
      lineas: [{ descripcion: "Ventas tienda " + periodo, cantidad: 1, precioUnitario: sub, tipoIVA: 0, exento: true, descuento: 0, aplicarRecargo: false }],
      retencionPct: 0,
      aplicarRecargo: false,
      notas,
      cobrado: true,
      pagado: true,
      costeMercancia: cos,
      impuestoManual: imp,
    });
  };

  const fmt = (n) => n.toLocaleString("es-ES", { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + " \u20ac";

  return (
    <div className="bg-white rounded-2xl border border-gray-200 p-6 max-w-3xl mx-auto shadow-sm">
      {/* Cabecera */}
      <div className="mb-6">
        <div className="flex items-center gap-2 mb-1">
          <span className="bg-violet-600 text-white text-xs font-black px-2.5 py-1 rounded-lg uppercase tracking-wide">Ventas de tienda</span>
          <span className="text-xs text-gray-400">Resumen mensual</span>
        </div>
        <h2 className="text-xl font-black text-gray-900">{initial ? "Editar ventas de tienda" : "Registrar ventas mensuales de tienda"}</h2>
        <p className="text-xs text-gray-400 mt-0.5">Introduce los totales del mes tal como salen de tu sistema de caja</p>
      </div>

      {/* Selector mes/anio */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Mes</label>
          <select className="w-full border rounded-xl px-3 py-2.5 text-sm font-semibold focus:ring-2 focus:ring-violet-300 outline-none"
            value={mes} onChange={e => setMes(parseInt(e.target.value))}>
            {MESES_NOMBRE.map((m, i) => <option key={i} value={i}>{m}</option>)}
          </select>
        </div>
        <div>
          <label className="text-xs font-semibold text-gray-500 block mb-1.5">Ano</label>
          <input type="number" min="2020" max="2040" className="w-full border rounded-xl px-3 py-2.5 text-sm font-mono font-semibold focus:ring-2 focus:ring-violet-300 outline-none"
            value={anio} onChange={e => setAnio(parseInt(e.target.value))}/>
        </div>
      </div>

      {yaExiste && (
        <div className="bg-amber-50 border border-amber-300 text-amber-800 text-sm px-4 py-3 rounded-xl mb-5 font-semibold">
          Ya existe un registro de ventas para {MESES_NOMBRE[mes]} {anio}. Si continuas se rechazara. Edita el registro existente o cambia el mes.
        </div>
      )}

      {/* Campos de importes */}
      <div className="space-y-4 mb-6">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="text-xs font-semibold text-gray-600 block mb-1.5">Subtotal (ventas sin impuesto) *</label>
            <div className="relative">
              <input type="number" min="0" step="0.01"
                className="w-full border-2 border-violet-200 rounded-xl px-3 py-3 text-sm font-mono font-bold bg-violet-50 focus:ring-2 focus:ring-violet-400 focus:border-violet-400 outline-none"
                placeholder="0.00" value={subtotal} onChange={e => setSubtotal(e.target.value)}/>
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-violet-400 text-sm font-bold">{"\u20ac"}</span>
            </div>
            <p className="text-xs text-gray-400 mt-1">Base imponible total del mes</p>
          </div>
          <div>
            <label className="text-xs font-semibold text-gray-600 block mb-1.5">Impuesto (IVA total) *</label>
            <div className="relative">
              <input type="number" min="0" step="0.01"
                className="w-full border-2 border-sky-200 rounded-xl px-3 py-3 text-sm font-mono font-bold bg-sky-50 focus:ring-2 focus:ring-sky-400 focus:border-sky-400 outline-none"
                placeholder="0.00" value={impuesto} onChange={e => setImpuesto(e.target.value)}/>
              <span className="absolute right-3 top-1/2 -translate-y-1/2 text-sky-400 text-sm font-bold">{"\u20ac"}</span>
            </div>
            <p className="text-xs text-gray-400 mt-1">Importe total del IVA (sin desglosar)</p>
          </div>
        </div>

        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Coste de mercancia *</label>
          <div className="relative">
            <input type="number" min="0" step="0.01"
              className="w-full border-2 border-rose-200 rounded-xl px-3 py-3 text-sm font-mono font-bold bg-rose-50 focus:ring-2 focus:ring-rose-400 focus:border-rose-400 outline-none"
              placeholder="0.00" value={coste} onChange={e => setCoste(e.target.value)}/>
            <span className="absolute right-3 top-1/2 -translate-y-1/2 text-rose-400 text-sm font-bold">{"\u20ac"}</span>
          </div>
          <p className="text-xs text-gray-400 mt-1">Lo que te costo comprar la mercancia vendida este mes</p>
        </div>

        <div>
          <label className="text-xs font-semibold text-gray-600 block mb-1.5">Notas (opcional)</label>
          <textarea className="w-full border border-gray-200 rounded-xl px-3 py-2 text-sm focus:ring-2 focus:ring-slate-300 outline-none resize-none" rows={2}
            placeholder="Observaciones, incidencias del mes..." value={notas} onChange={e => setNotas(e.target.value)}/>
        </div>
      </div>

      {/* Resumen calculado */}
      {sub > 0 && (
        <div className="bg-gradient-to-br from-violet-50 to-indigo-50 border border-violet-200 rounded-xl p-5 mb-6">
          <div className="text-xs font-black text-violet-700 uppercase tracking-wider mb-3">Resumen - {MESES_NOMBRE[mes]} {anio}</div>
          <div className="space-y-2 text-sm">
            <div className="flex justify-between text-gray-700"><span>Subtotal (sin impuesto)</span><span className="font-bold font-mono">{fmt(sub)}</span></div>
            <div className="flex justify-between text-gray-700"><span>Impuesto (IVA)</span><span className="font-bold font-mono text-sky-700">+{fmt(imp)}</span></div>
            <div className="flex justify-between text-gray-700 border-t border-violet-200 pt-2"><span className="font-bold">Total venta</span><span className="font-black font-mono text-lg">{fmt(totalVenta)}</span></div>
            <div className="flex justify-between text-gray-700 mt-3 border-t border-violet-200 pt-2"><span>Coste mercancia</span><span className="font-bold font-mono text-rose-600">-{fmt(cos)}</span></div>
            <div className={`flex justify-between text-lg font-black border-t-2 border-violet-300 pt-2 mt-2 ${beneficio >= 0 ? "text-emerald-700" : "text-rose-700"}`}>
              <span>Beneficio</span><span className="font-mono">{fmt(beneficio)}</span>
            </div>
            {sub > 0 && cos > 0 && (
              <div className="text-xs text-violet-600 text-right">Margen: {((beneficio / sub) * 100).toFixed(1)}%</div>
            )}
          </div>
        </div>
      )}

      <div className="flex gap-3 justify-end">
        <button onClick={onCancel} className="px-5 py-2.5 text-sm font-semibold border rounded-xl text-gray-600 hover:bg-gray-50">Cancelar</button>
        <button onClick={save} disabled={yaExiste || sub <= 0}
          className={`px-6 py-2.5 text-sm font-black rounded-xl shadow-lg ${yaExiste || sub <= 0 ? "bg-gray-300 text-gray-500 cursor-not-allowed" : "bg-violet-600 text-white hover:bg-violet-500"}`}>
          {initial ? "Guardar cambios" : "Registrar ventas"}
        </button>
      </div>
    </div>
  );
}

// Wrapper que decide qué formulario mostrar según modo
function FacturaForm({ actividades, facturas, onSave, onCancel, initial, logo, setLogo, contactos=[], userId }) {
  const [modo, setModo] = useState(() => {
    if (initial?.tipoDoc === "venta_tienda") return "tienda";
    return initial?.modo || "emitida";
  });
  if (!initial) {
    return (
      <div className="max-w-5xl mx-auto">
        {/* Selector de modo */}
        <div className="grid grid-cols-3 gap-4 mb-6">
          {[
            { m:"emitida",  label:"Crear factura de empresa",    sub:"Facturas que tú emites a clientes · Numeración DC-"+cy+"/NNNN · Con logotipo", color:"emerald", icon:"🧾" },
            { m:"recibida", label:"Registrar documento recibido", sub:"Facturas de proveedores, autofacturas (Amazon, Ría, Wester...), tickets", color:"rose", icon:"📥" },
            { m:"tienda",   label:"Ventas de tienda",            sub:"Resumen mensual · Subtotal, impuesto, coste y beneficio", color:"violet", icon:"🏪" },
          ].map(opt => (
            <button key={opt.m} onClick={() => setModo(opt.m)}
              className={`text-left p-5 rounded-2xl border-2 transition-all ${modo===opt.m
                ? opt.m==="emitida" ? "border-emerald-500 bg-emerald-50 shadow-md"
                : opt.m==="recibida" ? "border-rose-500 bg-rose-50 shadow-md"
                : "border-violet-500 bg-violet-50 shadow-md"
                : "border-gray-200 bg-white hover:border-gray-300"}`}>
              <div className="text-2xl mb-2">{opt.icon}</div>
              <div className={`font-black text-base ${modo===opt.m
                ? opt.m==="emitida"?"text-emerald-800":opt.m==="recibida"?"text-rose-800":"text-violet-800"
                : "text-gray-800"}`}>{opt.label}</div>
              <div className="text-xs text-gray-500 mt-1 leading-relaxed">{opt.sub}</div>
            </button>
          ))}
        </div>
        {modo==="emitida"
          ? <FacturaEmitidaForm actividades={actividades} facturas={facturas} onSave={onSave} onCancel={onCancel} logo={logo} setLogo={setLogo} contactos={contactos}/>
          : modo==="recibida"
          ? <DocumentoRecibidoForm actividades={actividades} onSave={onSave} onCancel={onCancel} contactos={contactos} userId={userId}/>
          : <VentaTiendaForm facturas={facturas} onSave={onSave} onCancel={onCancel}/>
        }
      </div>
    );
  }
  // Edición: usa el formulario correspondiente al modo/tipo original
  if (initial.tipoDoc === "venta_tienda") return <VentaTiendaForm facturas={facturas} onSave={onSave} onCancel={onCancel} initial={initial}/>;
  return initial.modo === "emitida"
    ? <FacturaEmitidaForm actividades={actividades} facturas={facturas} onSave={onSave} onCancel={onCancel} initial={initial} logo={logo} setLogo={setLogo} contactos={contactos}/>
    : <DocumentoRecibidoForm actividades={actividades} onSave={onSave} onCancel={onCancel} initial={initial} contactos={contactos} userId={userId}/>;
}

// ════════════════════════════════════════════════════════════
// VISTA: SALDOS PENDIENTES
// ════════════════════════════════════════════════════════════

function SaldoRow({ f, tipo, onView, onMarcarCobrado, onMarcarPagado }) {
  const t = calcFacturaReal(f);
  const diasDesde = Math.floor((new Date() - new Date(f.fecha)) / 86400000);
  const urgente   = diasDesde > 30;
  return (
    <tr className={`border-t border-gray-100 hover:bg-gray-50 transition-colors group cursor-pointer ${urgente?"bg-rose-50/30":""}`} onClick={() => onView(f)}>
      <td className="py-3 px-4">
        <div className="font-mono text-xs font-bold text-gray-600">{f.numero}</div>
        <div className="text-xs text-gray-400">{new Date(f.fecha).toLocaleDateString("es-ES")}</div>
      </td>
      <td className="py-3 px-4">
        <div className="font-semibold text-gray-800">{f.cliente}</div>
        {f.nif&&<div className="text-xs text-gray-400 font-mono">{f.nif}</div>}
      </td>
      <td className="py-3 px-4"><Tag color="gray">{f.actividad}</Tag></td>
      <td className="py-3 px-4 text-right font-black font-mono text-gray-900">{fmt(t.total)}</td>
      <td className="py-3 px-4 text-right">
        <span className={`text-xs font-bold ${urgente?"text-rose-600":"text-amber-600"}`}>{diasDesde} días</span>
      </td>
      <td className="py-3 px-4 text-right" onClick={e=>e.stopPropagation()}>
        <button
          onClick={() => tipo==="cobro" ? onMarcarCobrado(f.id) : onMarcarPagado(f.id)}
          className={`flex items-center gap-1.5 text-xs font-bold px-3 py-1.5 rounded-lg opacity-0 group-hover:opacity-100 transition-all ${tipo==="cobro"?"bg-emerald-50 text-emerald-700 hover:bg-emerald-100 border border-emerald-200":"bg-sky-50 text-sky-700 hover:bg-sky-100 border border-sky-200"}`}>
          {Ico.check} {tipo==="cobro"?"Marcar cobrada":"Marcar pagada"}
        </button>
      </td>
    </tr>
  );
}

function VistaSaldosPendientes({ facturas, onMarcarCobrado, onMarcarPagado, onView }) {
  const pendCobro = useMemo(() => facturas.filter(f => f.tipo==="venta" && !f.cobrado).sort((a,b) => new Date(a.fecha)-new Date(b.fecha)), [facturas]);
  const pendPago  = useMemo(() => facturas.filter(f => f.tipo==="gasto" && !f.pagado).sort((a,b) => new Date(a.fecha)-new Date(b.fecha)), [facturas]);

  const totalCobro = pendCobro.reduce((s,f) => s + calcFacturaReal(f).total, 0);
  const totalPago  = pendPago.reduce( (s,f) => s + calcFacturaReal(f).total, 0);



  return (
    <div className="space-y-8">
      {/* KPIs */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        <KPI label="Pendiente cobro" value={fmt(totalCobro)} tint="orange" sub={`${pendCobro.length} factura${pendCobro.length!==1?"s":""}`}/>
        <KPI label="Pendiente pago" value={fmt(totalPago)} tint="red" sub={`${pendPago.length} factura${pendPago.length!==1?"s":""}`}/>
        <KPI label="Saldo neto pendiente" value={fmt(totalCobro - totalPago)} sub="Cobros - pagos" accent/>
        <KPI label="Facturas totales" value={String(pendCobro.length + pendPago.length)} sub="Requieren acción" tint="amber"/>
      </div>

      {/* Pendiente de cobro */}
      {pendCobro.length > 0 && (
        <div>
          <Divider label={`Pendiente de cobro - ${fmt(totalCobro)}`}/>
          <div className="bg-white border border-orange-200 rounded-2xl overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-orange-50 border-b border-orange-200">
                <tr>{["Factura","Cliente","Actividad","Importe","Antigüedad",""].map((h,i) => (
                  <th key={i} className={`py-3 px-4 text-xs font-semibold text-orange-600 uppercase tracking-wide ${i<3?"text-left":"text-right"}`}>{h}</th>
                ))}</tr>
              </thead>
              <tbody>{pendCobro.map(f => <SaldoRow key={f.id} f={f} tipo="cobro" onView={onView} onMarcarCobrado={onMarcarCobrado} onMarcarPagado={onMarcarPagado}/>)}</tbody>
            </table>
          </div>
        </div>
      )}

      {/* Pendiente de pago */}
      {pendPago.length > 0 && (
        <div>
          <Divider label={`Pendiente de pago - ${fmt(totalPago)}`}/>
          <div className="bg-white border border-rose-200 rounded-2xl overflow-hidden shadow-sm">
            <table className="w-full text-sm">
              <thead className="bg-rose-50 border-b border-rose-200">
                <tr>{["Factura","Proveedor","Actividad","Importe","Antigüedad",""].map((h,i) => (
                  <th key={i} className={`py-3 px-4 text-xs font-semibold text-rose-600 uppercase tracking-wide ${i<3?"text-left":"text-right"}`}>{h}</th>
                ))}</tr>
              </thead>
              <tbody>{pendPago.map(f => <SaldoRow key={f.id} f={f} tipo="pago" onView={onView} onMarcarCobrado={onMarcarCobrado} onMarcarPagado={onMarcarPagado}/>)}</tbody>
            </table>
          </div>
        </div>
      )}

      {pendCobro.length===0 && pendPago.length===0 && (
        <div className="text-center py-24 bg-white border border-gray-100 rounded-2xl">
          <div className="text-6xl mb-4">✓</div>
          <div className="text-lg font-black text-gray-700">Sin saldos pendientes</div>
          <div className="text-sm text-gray-400 mt-2">Todas las facturas están cobradas o pagadas</div>
        </div>
      )}
    </div>
  );
}

