// ════════════════════════════════════════════════════════════
// CÁLCULO MODELO 347 - Operaciones con terceros > 3.005,06 €
// ════════════════════════════════════════════════════════════

const LIMITE_347 = 3005.06;

function calc347(facturas, year) {
  const mapa = {};
  facturas
    .filter(f => new Date(f.fecha).getFullYear() === year)
    .forEach(f => {
      const t = calcFacturaReal(f);
      const clave = (f.nif || f.cliente || "").toLowerCase().trim() || f.cliente.toLowerCase().trim();
      const nombre = f.cliente || "Sin nombre";
      const nif    = f.nif || "";
      if (!mapa[clave]) mapa[clave] = { nombre, nif, ventas:0, compras:0, nVentas:0, nCompras:0 };
      if (f.tipo === "venta") { mapa[clave].ventas   += t.totalBase; mapa[clave].nVentas++;  }
      else                    { mapa[clave].compras  += t.totalBase; mapa[clave].nCompras++; }
    });
  return Object.values(mapa)
    .map(r => ({ ...r, total: r.ventas + r.compras }))
    .filter(r => r.total >= LIMITE_347)
    .sort((a, b) => b.total - a.total);
}

// ════════════════════════════════════════════════════════════
// ALERTAS: IMPAGADOS + MODELO 347
// ════════════════════════════════════════════════════════════

function AlertasSistema({ facturas, onGoSaldos, onGo347, year }) {
  const hoy = new Date();

  // Impagados con más de 30 días
  const impagadosUrgentes = facturas.filter(f => {
    const isPend = f.tipo==="venta" ? !f.cobrado : !f.pagado;
    if (!isPend) return false;
    return Math.floor((hoy - new Date(f.fecha)) / 86400000) > 30;
  });
  const impagadosCriticos = impagadosUrgentes.filter(f =>
    Math.floor((hoy - new Date(f.fecha)) / 86400000) > 60
  );

  // 347 - nuevos superadores en el año actual
  const datos347 = calc347(facturas, year || cy);
  const nuevos347 = datos347.length;

  const alertas = [];
  if (impagadosCriticos.length > 0) alertas.push({ nivel:"critico", msg:`${impagadosCriticos.length} factura${impagadosCriticos.length!==1?"s":""} con más de 60 días sin cobrar/pagar`, sub:"Requiere acción inmediata", color:"rose", fn: onGoSaldos });
  else if (impagadosUrgentes.length > 0) alertas.push({ nivel:"alerta", msg:`${impagadosUrgentes.length} factura${impagadosUrgentes.length!==1?"s":""} pendientes con más de 30 días`, sub:"Revisa saldos pendientes", color:"amber", fn: onGoSaldos });
  if (nuevos347 > 0) alertas.push({ nivel:"info", msg:`${nuevos347} cliente${nuevos347!==1?"s/proveedores":" /proveedor"} superan 3.005 € en ${year||cy}`, sub:"Puede requerir presentar Modelo 347", color:"sky", fn: onGo347 });

  if (alertas.length === 0) return null;
  return (
    <div className="max-w-7xl mx-auto px-5 pt-4 space-y-2">
      {alertas.map((a, i) => {
        const bg = { rose:"bg-rose-50 border-rose-300 text-rose-900", amber:"bg-amber-50 border-amber-300 text-amber-900", sky:"bg-sky-50 border-sky-300 text-sky-900" }[a.color];
        const btn = { rose:"bg-rose-600 hover:bg-rose-500 text-white", amber:"bg-amber-600 hover:bg-amber-500 text-white", sky:"bg-sky-600 hover:bg-sky-500 text-white" }[a.color];
        const icon = { critico:"⚠", alerta:"🔔", info:"ℹ" }[a.nivel];
        return (
          <div key={i} className={`flex items-center gap-4 px-5 py-3.5 rounded-xl border ${bg} shadow-sm`}>
            <span className="text-lg">{icon}</span>
            <div className="flex-1 min-w-0">
              <span className="font-bold text-sm">{a.msg}</span>
              <span className="ml-2 text-xs opacity-70">{a.sub}</span>
            </div>
            <button onClick={a.fn} className={`flex-shrink-0 text-xs font-bold px-4 py-1.5 rounded-lg ${btn} transition-colors`}>Ver</button>
          </div>
        );
      })}
    </div>
  );
}

// ════════════════════════════════════════════════════════════
// VISTA MODELO 347
// ════════════════════════════════════════════════════════════

function Vista347({ facturas, year, availYears, onChangeYear }) {
  const [selectedYear, setSelectedYear] = useState(year || cy);
  const datos = useMemo(() => calc347(facturas, selectedYear), [facturas, selectedYear]);

  const totalVentas  = datos.reduce((s,r) => s+r.ventas, 0);
  const totalCompras = datos.reduce((s,r) => s+r.compras, 0);

  const handleYear = (y) => { setSelectedYear(y); if(onChangeYear) onChangeYear(y); };

  const generarCSV = () => {
    const head = "NIF;Nombre;Ventas (€);Compras (€);Total (€)\n";
    const rows  = datos.map(r => `${r.nif};${r.nombre};${r.ventas.toFixed(2)};${r.compras.toFixed(2)};${r.total.toFixed(2)}`).join("\n");
    const blob  = new Blob([head + rows], { type:"text/csv;charset=utf-8;" });
    const url   = URL.createObjectURL(blob);
    const a     = document.createElement("a");
    a.href      = url;
    a.download  = `Modelo347_${selectedYear}.csv`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 300);
  };

  const generarHTML = () => {
    const rows = datos.map(r => `<tr><td>${r.nif||"—"}</td><td><strong>${r.nombre}</strong></td><td style="text-align:right">${r.ventas.toFixed(2).replace(".",",")} €</td><td style="text-align:right">${r.compras.toFixed(2).replace(".",",")} €</td><td style="text-align:right;font-weight:900">${r.total.toFixed(2).replace(".",",")} €</td></tr>`).join("");
    const html = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Modelo 347 - ${selectedYear}</title>
    <style>body{font-family:sans-serif;font-size:12px;padding:24px}h1{font-size:16px}table{width:100%;border-collapse:collapse;margin-top:16px}th{background:#0f172a;color:#fff;padding:7px 10px;text-align:left;font-size:10px;text-transform:uppercase}td{padding:6px 10px;border-bottom:1px solid #e2e8f0}tr:nth-child(even) td{background:#f8fafc}.total{font-weight:900;font-size:14px;margin-top:12px;text-align:right}</style></head>
    <body><h1>Modelo 347 - Operaciones con terceros - Ejercicio ${selectedYear}</h1>
    <p style="color:#64748b;font-size:11px">Operaciones iguales o superiores a 3.005,06 € con el mismo proveedor o cliente durante el año. Solo bases imponibles, sin IVA.</p>
    <table><thead><tr><th>NIF/CIF</th><th>Nombre / Razón social</th><th style="text-align:right">Ventas (base)</th><th style="text-align:right">Compras (base)</th><th style="text-align:right">Total</th></tr></thead>
    <tbody>${rows}</tbody></table>
    <p class="total">Total operaciones declarables: ${datos.length} terceros · Ventas: ${totalVentas.toFixed(2).replace(".",",")} € · Compras: ${totalCompras.toFixed(2).replace(".",",")} €</p>
    <p style="margin-top:20px;font-size:10px;color:#94a3b8">Generado por ContaAuto · Documento de apoyo. Revisa con tu asesor antes de presentar el modelo oficial.</p>
    </body></html>`;
    const blob = new Blob([html], { type:"text/html;charset=utf-8" });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href     = url;
    a.download = `Modelo347_${selectedYear}.html`;
    a.click();
    setTimeout(() => URL.revokeObjectURL(url), 300);
  };

  return (
    <div className="space-y-6">
      {/* Cabecera */}
      <div className="bg-white border border-gray-200 rounded-2xl p-6 shadow-sm">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="bg-sky-700 text-white text-xs font-black px-2.5 py-1 rounded-lg uppercase tracking-wide">Modelo 347</span>
              <span className="text-xs text-gray-400">Declaración anual de operaciones con terceros</span>
            </div>
            <h2 className="text-xl font-black text-gray-900">Operaciones que superan 3.005 €</h2>
            <p className="text-xs text-gray-500 mt-1 max-w-xl">Clientes y proveedores con quienes el total de operaciones (bases imponibles, sin IVA) durante el ejercicio iguala o supera 3.005,06 €. Esta lista es la base para cumplimentar el Modelo 347 antes del último día de febrero del año siguiente.</p>
          </div>
          <div className="flex gap-2 flex-wrap">
            <button onClick={generarCSV}
              className="flex items-center gap-2 text-xs font-bold px-4 py-2.5 bg-emerald-600 hover:bg-emerald-500 text-white rounded-xl shadow-sm transition-colors">
              {Ico.down} Exportar CSV
            </button>
            <button onClick={generarHTML}
              className="flex items-center gap-2 text-xs font-bold px-4 py-2.5 bg-sky-600 hover:bg-sky-500 text-white rounded-xl shadow-sm transition-colors">
              {Ico.print} Descargar informe
            </button>
          </div>
        </div>

        {/* Selector de año */}
        <div className="flex items-center gap-2 mt-5 pt-5 border-t border-gray-100">
          <span className="text-xs font-bold text-gray-500 uppercase tracking-widest">Ejercicio</span>
          {(availYears || [cy-1, cy]).map(y => (
            <button key={y} onClick={() => handleYear(y)}
              className={`px-4 py-1.5 rounded-lg text-sm font-bold border transition-all ${selectedYear===y?"bg-slate-900 text-white border-slate-900":"border-gray-200 text-gray-500 hover:border-slate-400"}`}>
              {y}
            </button>
          ))}
        </div>
      </div>

      {/* KPIs */}
      {datos.length > 0 && (
        <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
          <KPI label="Terceros declarables" value={String(datos.length)} tint="amber" sub={`Superan 3.005,06 € en ${selectedYear}`}/>
          <KPI label="Total ventas declaradas" value={fmt(totalVentas)} tint="green" sub="Bases imponibles"/>
          <KPI label="Total compras declaradas" value={fmt(totalCompras)} tint="red" sub="Bases imponibles"/>
          <KPI label="Volumen total declarable" value={fmt(totalVentas+totalCompras)} accent sub="Ventas + compras"/>
        </div>
      )}

      {/* Tabla */}
      {datos.length === 0 ? (
        <div className="text-center py-20 bg-white border border-gray-100 rounded-2xl">
          <div className="text-5xl mb-3">✓</div>
          <div className="text-base font-bold text-gray-700 mb-1">Sin obligación de declarar en {selectedYear}</div>
          <div className="text-sm text-gray-400">Ningún cliente ni proveedor supera los 3.005,06 € en bases imponibles acumuladas.</div>
        </div>
      ) : (
        <div className="bg-white border border-gray-200 rounded-2xl overflow-hidden shadow-sm">
          <div className="px-5 py-3 bg-sky-900 text-white text-xs font-bold uppercase tracking-widest">
            {datos.length} tercero{datos.length!==1?"s":""} declarable{datos.length!==1?"s":""} · Ejercicio {selectedYear}
          </div>
          <table className="w-full text-sm">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                {["NIF / CIF","Nombre / Razón social","Fact.","Ventas (base)","Compras (base)","Total operaciones","Clave"].map((h,i) => (
                  <th key={i} className={`py-3 px-4 text-xs font-semibold text-gray-500 uppercase tracking-wide ${i<=1?"text-left":"text-right"} ${i===6?"text-center":""}`}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {datos.map((r,i) => (
                <tr key={i} className={`border-t border-gray-100 hover:bg-sky-50/30 transition-colors ${r.total>=10000?"bg-amber-50/20":""}`}>
                  <td className="py-3 px-4 font-mono text-xs text-gray-500">{r.nif || <span className="italic text-gray-300">Sin NIF</span>}</td>
                  <td className="py-3 px-4 font-semibold text-gray-900">{r.nombre}</td>
                  <td className="py-3 px-4 text-right text-xs text-gray-400">{r.nVentas+r.nCompras}</td>
                  <td className="py-3 px-4 text-right font-semibold text-emerald-700 font-mono">{r.ventas>0?fmt(r.ventas):"—"}</td>
                  <td className="py-3 px-4 text-right font-semibold text-rose-600 font-mono">{r.compras>0?fmt(r.compras):"—"}</td>
                  <td className="py-3 px-4 text-right font-black font-mono text-gray-900">{fmt(r.total)}</td>
                  <td className="py-3 px-4 text-center">
                    {r.ventas>0&&r.compras>0
                      ? <Tag color="violet">A+B</Tag>
                      : r.ventas>0
                        ? <Tag color="green">A - Ventas</Tag>
                        : <Tag color="red">B - Compras</Tag>
                    }
                  </td>
                </tr>
              ))}
            </tbody>
            <tfoot className="bg-gray-100 border-t border-gray-300">
              <tr>
                <td colSpan={3} className="py-3 px-4 text-xs font-black text-gray-600 uppercase">Totales</td>
                <td className="py-3 px-4 text-right font-black font-mono text-emerald-800">{fmt(totalVentas)}</td>
                <td className="py-3 px-4 text-right font-black font-mono text-rose-800">{fmt(totalCompras)}</td>
                <td className="py-3 px-4 text-right font-black font-mono text-gray-900">{fmt(totalVentas+totalCompras)}</td>
                <td/>
              </tr>
            </tfoot>
          </table>
          <div className="px-5 py-3 bg-sky-50 border-t border-sky-200 text-xs text-sky-800">
            Clave A: operaciones de venta · Clave B: operaciones de compra · Clave A+B: figura en ambas cuentas. El Modelo 347 se presenta en febrero del año siguiente al ejercicio declarado.
          </div>
        </div>
      )}
    </div>
  );
}



