const MESES_ES = ["Enero","Febrero","Marzo","Abril","Mayo","Junio","Julio","Agosto","Septiembre","Octubre","Noviembre","Diciembre"];

// ── Parser universal de extractos bancarios españoles ──────
function parsearExtracto(raw) {
  const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);
  const movs  = [];
  // detectar cabecera (primera línea con letras sin importe)
  let skipFirst = false;
  if (lines.length > 1) {
    const primero = lines[0].replace(/"/g,"");
    if (!/[0-9]/.test(primero) || /fecha|concepto|importe|saldo|date|amount|valor/i.test(primero)) skipFirst = true;
  }
  for (let li = skipFirst ? 1 : 0; li < lines.length; li++) {
    const raw = lines[li];
    let cols = raw.includes(";") ? raw.split(";") : raw.includes("\t") ? raw.split("\t") : raw.split(",");
    cols = cols.map(c => c.replace(/^"|"$/g,"").trim());
    if (cols.length < 2) continue;
    let fecha = "", concepto = "", importe = null, saldo = null;
    for (const v of cols) {
      // fecha
      if (/^\d{1,2}[\/\-\.]\d{1,2}[\/\-\.]\d{2,4}$/.test(v) || /^\d{4}[\/\-]\d{2}[\/\-]\d{2}$/.test(v)) { if (!fecha) fecha = v; continue; }
      // importe: número con coma o punto decimal, posible signo, posible separador de miles
      const n = parseFloat(v.replace(/\./g,"").replace(",",".").replace(/\s/g,""));
      if (!isNaN(n) && v !== "" && /[\d,\.]/.test(v)) {
        if (importe === null) importe = n;
        else if (saldo === null) saldo = n;
        continue;
      }
      if (v.length > 1) concepto = concepto ? concepto + " " + v : v;
    }
    if (importe !== null && Math.abs(importe) > 0) {
      movs.push({ fecha, concepto: concepto || "Sin descripción", importe, saldo });
    }
  }
  return movs;
}

// ── Categorización automática de movimientos ──────────────
const CATS_BANCO = [
  { id:"seguridad_social", label:"Seguridad Social / TGSS", color:"violet",  patterns:[/tgss|seguridad social|cuota autonomo|reta|mutua|coleg/i] },
  { id:"hacienda",         label:"AEAT / Hacienda",         color:"rose",    patterns:[/aeat|agencia tributaria|mod\s*\d{3}|hacienda|irpf|iva\s+trimestral|modelo/i] },
  { id:"suministros",      label:"Suministros (luz/agua/gas)",color:"amber", patterns:[/endesa|iberdrola|naturgy|gas natural|repsol|acciona|e\.on|r\s*energia|hidroelectrica|enel|sevillana|hidrocantabrico|aqualia|aguas|canal.*isabel|agbar/i] },
  { id:"telecomunicaciones",label:"Telecomunicaciones",     color:"sky",     patterns:[/movistar|vodafone|orange|masmovil|digi|yoigo|jazztel|fibra|telefonica|sim\s*card/i] },
  { id:"nominas",          label:"Nóminas / Personal",      color:"indigo",  patterns:[/nomina|salario|haberes|trabajador|empleado/i] },
  { id:"alquiler",         label:"Alquiler",                color:"teal",    patterns:[/alquiler|arrendamiento|inquilino|propietario|mensualidad piso|local/i] },
  { id:"financiero",       label:"Financiero / Bancario",   color:"slate",   patterns:[/cuota prestamo|cuota hipoteca|leasing|renting|interes|comision banco|mantenimiento cuenta|tae|tin|amortiz/i] },
  { id:"seguros",          label:"Seguros",                 color:"cyan",    patterns:[/seguro|prima|aseguradora|mapfre|axa|allianz|zurich|sanitas|adeslas|mutua.*madrilena/i] },
  { id:"ingresos_clientes",label:"Ingresos clientes",       color:"emerald", patterns:[/transferencia recibida|abono|ingreso|cobro factura|honorarios recibidos/i] },
  { id:"proveedores",      label:"Proveedores / Compras",   color:"orange",  patterns:[/proveedor|compra|suministro|material|factura proveedor|amazon|aliexpress/i] },
  { id:"autonomo_gastos",  label:"Gastos profesionales",    color:"purple",  patterns:[/software|licencia|suscripcion|herramienta|formacion|curso|colegio.*profesional|asociacion/i] },
  { id:"tarjeta",          label:"Tarjeta / TPV",           color:"pink",    patterns:[/visa|mastercard|tarjeta|tpv|pago.*movil|bizum recibido|pago.*online/i] },
  { id:"otros",            label:"Otros",                   color:"gray",    patterns:[/.*/] },
];

function categorizarMov(mov) {
  for (const cat of CATS_BANCO) {
    if (cat.patterns.some(rx => rx.test(mov.concepto))) return cat;
  }
  return CATS_BANCO[CATS_BANCO.length - 1];
}

// ── Helpers de render ─────────────────────────────────────
function BadgeCategoria({ cat, small }) {
  const COLORS = {
    violet:"bg-violet-100 text-violet-700", rose:"bg-rose-100 text-rose-700",
    amber:"bg-amber-100 text-amber-700",   sky:"bg-sky-100 text-sky-700",
    indigo:"bg-indigo-100 text-indigo-700",teal:"bg-teal-100 text-teal-700",
    slate:"bg-slate-100 text-slate-700",   cyan:"bg-cyan-100 text-cyan-700",
    emerald:"bg-emerald-100 text-emerald-700", orange:"bg-orange-100 text-orange-700",
    purple:"bg-purple-100 text-purple-700", pink:"bg-pink-100 text-pink-700",
    gray:"bg-gray-100 text-gray-600",
  };
  return <span className={`inline-block font-bold rounded-full ${small?"text-xs px-2 py-0.5":"text-xs px-2.5 py-1"} ${COLORS[cat.color]||COLORS.gray}`}>{cat.label}</span>;
}

