    violet:  { ring:"ring-violet-500/40",  hover:"hover:border-violet-500/50",  icon:"text-violet-400",  badgeBg:"bg-violet-950/60 text-violet-300",  btn:"bg-violet-500 hover:bg-violet-400" },
    amber:   { ring:"ring-amber-500/40",   hover:"hover:border-amber-500/50",   icon:"text-amber-400",   badgeBg:"bg-amber-950/60 text-amber-300",   btn:"bg-amber-400 hover:bg-amber-300" },
